if (typeof TOEIC_QUESTIONS !== 'undefined') {

  const EXTRA_PART5 = [

    // ──────────────────────────────────────────────
    // VERB-TENSE (Unit 1 – Business Foundations)
    // ──────────────────────────────────────────────
    { id:"ex-vt-01", type:"verb-tense", question:"By the time the CEO arrived, the board members _____ waiting for an hour.", options:["have been","had been","were","are"], answer:1, explanation:"Past perfect continuous diễn tả hành động xảy ra liên tục trước một thời điểm trong quá khứ." },
    { id:"ex-vt-02", type:"verb-tense", question:"The company _____ its annual report every December since it was founded.", options:["publishes","has published","published","will publish"], answer:1, explanation:"'Since' + khoảng thời gian → dùng Present Perfect." },
    { id:"ex-vt-03", type:"verb-tense", question:"Sales figures _____ dramatically last quarter compared to the same period last year.", options:["rise","have risen","rose","will rise"], answer:2, explanation:"'Last quarter' là dấu hiệu thì Past Simple." },
    { id:"ex-vt-04", type:"verb-tense", question:"If the merger _____ approved, both companies will need to restructure.", options:["is","was","were","will be"], answer:0, explanation:"Câu điều kiện loại 1: If + hiện tại đơn, will + động từ nguyên thể." },
    { id:"ex-vt-05", type:"verb-tense", question:"The client _____ the proposal by 5 p.m. tomorrow, so we must finish it today.", options:["expects","will be expecting","has expected","expected"], answer:1, explanation:"Future Continuous diễn tả hành động đang xảy ra tại thời điểm cụ thể trong tương lai." },
    { id:"ex-vt-06", type:"verb-tense", question:"Our team _____ on this project for three months when the deadline finally arrives.", options:["will work","will have been working","has worked","works"], answer:1, explanation:"Future Perfect Continuous nhấn mạnh thời gian kéo dài đến một điểm trong tương lai." },
    { id:"ex-vt-07", type:"verb-tense", question:"The director _____ the office to the new location last Friday.", options:["moves","moved","has moved","is moving"], answer:1, explanation:"'Last Friday' xác định thì Past Simple." },
    { id:"ex-vt-08", type:"verb-tense", question:"Profits _____ steadily since the new strategy was implemented.", options:["grow","grew","have grown","will grow"], answer:2, explanation:"'Since' + mốc quá khứ → Present Perfect." },
    { id:"ex-vt-09", type:"verb-tense", question:"While the accountant _____ the budget, she noticed an error.", options:["reviewed","was reviewing","has reviewed","reviews"], answer:1, explanation:"Past Continuous diễn tả hành động đang xảy ra khi một hành động khác xen vào." },
    { id:"ex-vt-10", type:"verb-tense", question:"The factory _____ over 10,000 units per day at full capacity.", options:["produced","has produced","produces","had produced"], answer:2, explanation:"Sự thật / thói quen hiện tại → Present Simple." },
    { id:"ex-vt-11", type:"verb-tense", question:"By next year, the company _____ its 50th anniversary.", options:["celebrates","will celebrate","has celebrated","celebrated"], answer:1, explanation:"'By next year' + thì Future Simple." },
    { id:"ex-vt-12", type:"verb-tense", question:"Management _____ to introduce flexible working hours next month.", options:["plans","planned","has planned","will have planned"], answer:0, explanation:"Kế hoạch sắp xảy ra trong tương lai gần dùng Present Simple." },
    { id:"ex-vt-13", type:"verb-tense", question:"The consultant _____ three different proposals before the board selected one.", options:["submits","submitted","has submitted","had submitted"], answer:3, explanation:"Past Perfect diễn tả hành động hoàn thành trước một hành động quá khứ khác." },
    { id:"ex-vt-14", type:"verb-tense", question:"She _____ the conference call when the power outage occurred.", options:["joins","joined","was joining","has joined"], answer:2, explanation:"Past Continuous bị gián đoạn bởi Past Simple." },
    { id:"ex-vt-15", type:"verb-tense", question:"The marketing team _____ the campaign materials by the end of this week.", options:["finish","will have finished","finished","has finished"], answer:1, explanation:"Future Perfect diễn tả hành động hoàn thành trước một thời điểm trong tương lai." },
    { id:"ex-vt-16", type:"verb-tense", question:"We _____ the contract yet because negotiations are still ongoing.", options:["don't sign","didn't sign","haven't signed","won't sign"], answer:2, explanation:"'Yet' trong câu phủ định → Present Perfect." },
    { id:"ex-vt-17", type:"verb-tense", question:"The new policy _____ effect as soon as the CEO signs it.", options:["takes","will take","took","has taken"], answer:0, explanation:"Mệnh đề 'as soon as' (thời gian) dùng Present Simple dù ý tương lai." },
    { id:"ex-vt-18", type:"verb-tense", question:"They _____ the system upgrade when the client called to report a bug.", options:["test","were testing","have tested","had tested"], answer:1, explanation:"Past Continuous bị gián đoạn." },
    { id:"ex-vt-19", type:"verb-tense", question:"The quarterly results _____ better than expected, pleasing all stakeholders.", options:["are","were","have been","will be"], answer:1, explanation:"Kết quả quý vừa rồi → Past Simple." },
    { id:"ex-vt-20", type:"verb-tense", question:"She _____ as CFO for the past decade and plans to retire next year.", options:["serves","served","has served","will serve"], answer:2, explanation:"'For the past decade' → Present Perfect." },

    // ──────────────────────────────────────────────
    // PASSIVE (Unit 2 – Office Life)
    // ──────────────────────────────────────────────
    { id:"ex-pv-01", type:"passive", question:"The annual report _____ by the finance team every December.", options:["prepares","is prepared","prepared","has prepared"], answer:1, explanation:"Chủ thể 'report' là vật thể bị tác động → bị động Present Simple." },
    { id:"ex-pv-02", type:"passive", question:"New employees _____ a full orientation before starting their assignments.", options:["give","are given","gave","have given"], answer:1, explanation:"'New employees' nhận được hành động → bị động." },
    { id:"ex-pv-03", type:"passive", question:"The office _____ last year to accommodate the growing team.", options:["expands","was expanded","has expanded","expanded"], answer:1, explanation:"Past Passive vì hành động xảy ra 'last year'." },
    { id:"ex-pv-04", type:"passive", question:"The meeting agenda _____ to all participants before the session begins.", options:["distributes","will be distributed","distributed","is distributing"], answer:1, explanation:"Future Passive: 'will be + past participle'." },
    { id:"ex-pv-05", type:"passive", question:"The software update _____ by IT staff every quarter.", options:["installs","is installed","installed","has installed"], answer:1, explanation:"Thói quen định kỳ + bị động." },
    { id:"ex-pv-06", type:"passive", question:"Staff are informed that personal items should _____ in the designated storage area.", options:["keep","be kept","keeping","have kept"], answer:1, explanation:"Modal + be + past participle = passive." },
    { id:"ex-pv-07", type:"passive", question:"The new workspace _____ to a contemporary open-plan design.", options:["has converted","was converted","converts","converted"], answer:1, explanation:"Past Simple Passive: 'was + past participle'." },
    { id:"ex-pv-08", type:"passive", question:"Complaints about workplace conditions must _____ to HR within 48 hours.", options:["report","be reported","reporting","have reported"], answer:1, explanation:"Modal passive: must + be + past participle." },
    { id:"ex-pv-09", type:"passive", question:"The printer on the third floor _____ since Monday due to a malfunction.", options:["is not used","has not been used","was not used","will not be used"], answer:1, explanation:"'Since Monday' → Present Perfect Passive." },
    { id:"ex-pv-10", type:"passive", question:"Visitors _____ to sign in at the reception desk upon arrival.", options:["require","are required","required","will require"], answer:1, explanation:"Bị động thể hiện quy định." },
    { id:"ex-pv-11", type:"passive", question:"The board meeting schedule _____ twice before the final date was confirmed.", options:["changed","was changed","has changed","is changed"], answer:1, explanation:"Past Passive nhấn mạnh lịch bị thay đổi." },
    { id:"ex-pv-12", type:"passive", question:"All expense reports must _____ by the end of the fiscal month.", options:["submit","be submitted","submitted","submitting"], answer:1, explanation:"Modal + be + past participle." },
    { id:"ex-pv-13", type:"passive", question:"The HR manual _____ to reflect the latest employment regulations.", options:["updated","has been updated","updates","is updating"], answer:1, explanation:"Present Perfect Passive diễn tả kết quả hiện tại." },
    { id:"ex-pv-14", type:"passive", question:"The conference room _____ for the board meeting at 10 a.m.", options:["is reserving","has been reserved","will reserve","reserves"], answer:1, explanation:"Present Perfect Passive: đã được đặt trước." },
    { id:"ex-pv-15", type:"passive", question:"Employees _____ encouraged to participate in the wellness program.", options:["are","were","have","is"], answer:0, explanation:"'Are encouraged' = Present Passive." },
    { id:"ex-pv-16", type:"passive", question:"The old photocopier _____ with a high-speed model last month.", options:["replaced","was replaced","has replaced","is replaced"], answer:1, explanation:"Past Passive + 'last month'." },
    { id:"ex-pv-17", type:"passive", question:"All packages _____ before they are delivered to individual departments.", options:["scan","are scanned","scanned","scanning"], answer:1, explanation:"Present Simple Passive cho quy trình định kỳ." },
    { id:"ex-pv-18", type:"passive", question:"The new safety guidelines _____ by management during the all-hands meeting.", options:["announced","were announced","have announced","will announce"], answer:1, explanation:"Past Passive diễn tả thông báo trong cuộc họp." },
    { id:"ex-pv-19", type:"passive", question:"Access to the server room can only _____ with a special security badge.", options:["gain","be gained","gained","gaining"], answer:1, explanation:"Modal + be + past participle." },
    { id:"ex-pv-20", type:"passive", question:"A formal invitation _____ to each department head prior to the annual dinner.", options:["send","was sent","has sent","sends"], answer:1, explanation:"Past Simple Passive." },

    // ──────────────────────────────────────────────
    // CONDITIONALS (Unit 3 – Personnel & HR)
    // ──────────────────────────────────────────────
    { id:"ex-cd-01", type:"conditionals", question:"If the candidate _____ the experience requirements, she will be shortlisted.", options:["meets","met","had met","would meet"], answer:0, explanation:"Điều kiện loại 1: If + Present Simple, will + V." },
    { id:"ex-cd-02", type:"conditionals", question:"If we _____ more staff, we could handle the project more efficiently.", options:["hire","hired","had hired","have hired"], answer:1, explanation:"Điều kiện loại 2: If + Past Simple, could + V." },
    { id:"ex-cd-03", type:"conditionals", question:"The team _____ the deadline if they had received the files earlier.", options:["would meet","would have met","will meet","meets"], answer:1, explanation:"Điều kiện loại 3: If + Past Perfect, would have + past participle." },
    { id:"ex-cd-04", type:"conditionals", question:"Should you require further information, please _____ the HR department.", options:["contact","contacted","will contact","contacting"], answer:0, explanation:"'Should' đảo ngữ = If you should... → yêu cầu, mệnh đề sau dùng V nguyên thể." },
    { id:"ex-cd-05", type:"conditionals", question:"Were the budget _____, the company would hire ten more employees.", options:["larger","the largest","most large","so large"], answer:0, explanation:"Điều kiện loại 2 đảo ngữ: Were + S + adj/noun." },
    { id:"ex-cd-06", type:"conditionals", question:"If the training program _____ successful, it will be rolled out company-wide.", options:["proves","proved","had proved","was proving"], answer:0, explanation:"Điều kiện loại 1." },
    { id:"ex-cd-07", type:"conditionals", question:"Had the applicant _____ the portfolio earlier, she might have been hired.", options:["submits","submitted","submit","submitting"], answer:1, explanation:"Điều kiện loại 3 đảo ngữ: Had + S + past participle." },
    { id:"ex-cd-08", type:"conditionals", question:"Unless employees _____ the code of conduct, disciplinary action may follow.", options:["follow","followed","are followed","will follow"], answer:0, explanation:"Unless = if not → dùng Present Simple trong mệnh đề điều kiện." },
    { id:"ex-cd-09", type:"conditionals", question:"If the performance review _____ positive, she will receive a bonus.", options:["is","was","were","be"], answer:0, explanation:"Điều kiện loại 1: If + Present Simple." },
    { id:"ex-cd-10", type:"conditionals", question:"The company _____ more quickly if HR streamlined the onboarding process.", options:["grows","grew","would grow","will grow"], answer:2, explanation:"Điều kiện loại 2: would + V." },
    { id:"ex-cd-11", type:"conditionals", question:"Provided that all references _____ out, the offer will be made.", options:["check","checked","are checked","have checked"], answer:2, explanation:"'Provided that' + Present Passive = điều kiện loại 1." },
    { id:"ex-cd-12", type:"conditionals", question:"If she _____ the interview tomorrow, she would be very nervous.", options:["attends","attended","had attended","will attend"], answer:1, explanation:"Điều kiện loại 2 (giả định hiện tại/tương lai)." },
    { id:"ex-cd-13", type:"conditionals", question:"The layoffs _____ avoided had the company planned its budget more carefully.", options:["could be","could have been","can be","will have been"], answer:1, explanation:"Điều kiện loại 3: could have been + past participle." },
    { id:"ex-cd-14", type:"conditionals", question:"In case the applicant _____ the test, a retake will be offered.", options:["fails","failed","has failed","will fail"], answer:0, explanation:"'In case' + Present Simple trong câu điều kiện." },
    { id:"ex-cd-15", type:"conditionals", question:"If I _____ you, I would negotiate for a higher starting salary.", options:["am","were","was","be"], answer:1, explanation:"Điều kiện loại 2 với 'If I were you'." },
    { id:"ex-cd-16", type:"conditionals", question:"The department _____ the training budget if there are budget cuts.", options:["loses","would lose","will lose","lost"], answer:2, explanation:"Điều kiện loại 1: will + V." },
    { id:"ex-cd-17", type:"conditionals", question:"We _____ an outside consultant if our internal team had had more expertise.", options:["needn't hire","wouldn't have hired","won't hire","didn't hire"], answer:1, explanation:"Điều kiện loại 3: wouldn't have + past participle." },
    { id:"ex-cd-18", type:"conditionals", question:"As long as all documents _____, the visa application will proceed.", options:["are submitted","submit","submitted","will submit"], answer:0, explanation:"'As long as' + Present Passive = điều kiện loại 1." },
    { id:"ex-cd-19", type:"conditionals", question:"If the firm _____ to expand overseas, it would need additional legal counsel.", options:["plans","planned","would plan","will plan"], answer:1, explanation:"Điều kiện loại 2: If + Past Simple." },
    { id:"ex-cd-20", type:"conditionals", question:"The candidate _____ the position unless she improves her technical skills.", options:["won't get","wouldn't get","doesn't get","hadn't gotten"], answer:0, explanation:"'Unless' + Present Simple = điều kiện loại 1 phủ định." },

    // ──────────────────────────────────────────────
    // WORD-FORM (Unit 4 – Marketing & Sales)
    // ──────────────────────────────────────────────
    { id:"ex-wf-01", type:"word-form", question:"The new product launch was an outstanding _____ for the marketing team.", options:["achieve","achievement","achieved","achievable"], answer:1, explanation:"Sau mạo từ 'an' → cần danh từ 'achievement'." },
    { id:"ex-wf-02", type:"word-form", question:"The sales team showed remarkable _____ in handling difficult clients.", options:["profess","profession","professional","professionalism"], answer:3, explanation:"Cần danh từ trừu tượng sau tính từ 'remarkable'." },
    { id:"ex-wf-03", type:"word-form", question:"Marketing specialists must be _____ skilled in data analysis.", options:["particular","particularly","particulars","particularize"], answer:1, explanation:"Cần trạng từ bổ nghĩa cho tính từ 'skilled'." },
    { id:"ex-wf-04", type:"word-form", question:"The _____ of the new campaign exceeded all expectations.", options:["effect","effective","effectively","effectiveness"], answer:3, explanation:"Chủ ngữ của câu cần danh từ 'effectiveness'." },
    { id:"ex-wf-05", type:"word-form", question:"The brand's _____ among younger consumers has increased significantly.", options:["popular","popularize","popularity","popularly"], answer:2, explanation:"Chủ ngữ cần danh từ 'popularity'." },
    { id:"ex-wf-06", type:"word-form", question:"An _____ marketing strategy can dramatically increase brand awareness.", options:["effect","effectively","effective","effects"], answer:2, explanation:"Tính từ 'effective' bổ nghĩa cho danh từ 'strategy'." },
    { id:"ex-wf-07", type:"word-form", question:"The team's _____ to the new branding guidelines was immediate.", options:["adapt","adapted","adaptation","adaptable"], answer:2, explanation:"Cần danh từ làm chủ ngữ." },
    { id:"ex-wf-08", type:"word-form", question:"The company plans to _____ its product line to include eco-friendly options.", options:["expansion","expanded","expand","expanse"], answer:2, explanation:"Sau 'to' là động từ nguyên thể 'expand'." },
    { id:"ex-wf-09", type:"word-form", question:"Customers have shown strong _____ to the redesigned packaging.", options:["respond","responsive","responsiveness","response"], answer:3, explanation:"'Strong' + danh từ → 'response'." },
    { id:"ex-wf-10", type:"word-form", question:"The _____ of digital advertising has transformed the marketing landscape.", options:["rise","rising","risen","arose"], answer:0, explanation:"'The' + danh từ 'rise' làm chủ ngữ." },
    { id:"ex-wf-11", type:"word-form", question:"She has a great _____ for identifying emerging market trends.", options:["able","ability","ably","enables"], answer:1, explanation:"'A great' + danh từ → 'ability'." },
    { id:"ex-wf-12", type:"word-form", question:"The launch event was _____ attended by over five hundred people.", options:["well","good","better","best"], answer:0, explanation:"Trạng từ 'well' bổ nghĩa cho động từ 'attended'." },
    { id:"ex-wf-13", type:"word-form", question:"The campaign created significant _____ about the new product line.", options:["aware","awareness","awaken","awares"], answer:1, explanation:"Danh từ 'awareness' sau tính từ 'significant'." },
    { id:"ex-wf-14", type:"word-form", question:"A _____ analysis of the market data revealed new growth opportunities.", options:["comprehend","comprehensive","comprehensively","comprehension"], answer:1, explanation:"Tính từ 'comprehensive' bổ nghĩa cho danh từ 'analysis'." },
    { id:"ex-wf-15", type:"word-form", question:"The marketing director spoke _____ about the importance of customer retention.", options:["passionate","passionately","passion","passioned"], answer:1, explanation:"Trạng từ 'passionately' bổ nghĩa cho động từ 'spoke'." },
    { id:"ex-wf-16", type:"word-form", question:"The _____ of the new ad campaign was met with positive reviews.", options:["release","releasing","released","releases"], answer:0, explanation:"'The' + danh từ 'release'." },
    { id:"ex-wf-17", type:"word-form", question:"Sales figures indicate a _____ trend in consumer demand.", options:["grow","grown","growing","growth"], answer:2, explanation:"Tính từ dạng -ing 'growing' bổ nghĩa cho 'trend'." },
    { id:"ex-wf-18", type:"word-form", question:"The _____ team submitted their quarterly projections ahead of schedule.", options:["finance","financial","financing","financed"], answer:1, explanation:"Tính từ 'financial' bổ nghĩa cho danh từ 'team'." },
    { id:"ex-wf-19", type:"word-form", question:"The product _____ has been overwhelmingly positive according to surveys.", options:["receive","reception","received","receptive"], answer:1, explanation:"Danh từ 'reception' làm chủ ngữ." },
    { id:"ex-wf-20", type:"word-form", question:"The strategy was _____ designed to appeal to international consumers.", options:["specific","specifically","specifying","specifics"], answer:1, explanation:"Trạng từ 'specifically' bổ nghĩa cho 'designed'." },

    // ──────────────────────────────────────────────
    // PREPOSITIONS (Unit 5 – Finance & Budget)
    // ──────────────────────────────────────────────
    { id:"ex-pp-01", type:"prepositions", question:"The finance department submitted the budget proposal _____ schedule.", options:["ahead of","next to","due to","in spite of"], answer:0, explanation:"'Ahead of schedule' = trước thời hạn." },
    { id:"ex-pp-02", type:"prepositions", question:"The company's profit increased _____ 12% last fiscal year.", options:["by","to","for","at"], answer:0, explanation:"Tăng/giảm theo tỷ lệ dùng 'by'." },
    { id:"ex-pp-03", type:"prepositions", question:"Investors are concerned _____ the rising interest rates.", options:["about","of","at","on"], answer:0, explanation:"'Concerned about' = lo ngại về." },
    { id:"ex-pp-04", type:"prepositions", question:"The budget was allocated _____ different departments based on their needs.", options:["across","along","over","through"], answer:0, explanation:"'Allocated across' = phân bổ cho nhiều bộ phận." },
    { id:"ex-pp-05", type:"prepositions", question:"The invoice must be paid _____ 30 days of receipt.", options:["within","until","during","after"], answer:0, explanation:"'Within 30 days' = trong vòng 30 ngày." },
    { id:"ex-pp-06", type:"prepositions", question:"The CFO presented the financial results _____ behalf of the CEO.", options:["on","in","at","for"], answer:0, explanation:"'On behalf of' = thay mặt cho." },
    { id:"ex-pp-07", type:"prepositions", question:"The shares are currently trading _____ a premium.", options:["at","in","on","by"], answer:0, explanation:"'Trading at a premium' = giao dịch ở mức giá cao hơn." },
    { id:"ex-pp-08", type:"prepositions", question:"The company has been operating _____ a loss for two consecutive quarters.", options:["at","in","on","with"], answer:0, explanation:"'Operating at a loss' = hoạt động thua lỗ." },
    { id:"ex-pp-09", type:"prepositions", question:"She is responsible _____ overseeing the company's financial reporting.", options:["for","of","about","in"], answer:0, explanation:"'Responsible for' = chịu trách nhiệm về." },
    { id:"ex-pp-10", type:"prepositions", question:"The board approved the proposal _____ a vote of 7 to 2.", options:["by","with","in","at"], answer:0, explanation:"'By a vote' = thông qua bỏ phiếu." },
    { id:"ex-pp-11", type:"prepositions", question:"Expenses were cut _____ order to improve the bottom line.", options:["in","by","for","on"], answer:0, explanation:"'In order to' = để, nhằm mục đích." },
    { id:"ex-pp-12", type:"prepositions", question:"The company's revenue is _____ line with analysts' expectations.", options:["in","on","at","by"], answer:0, explanation:"'In line with' = phù hợp với." },
    { id:"ex-pp-13", type:"prepositions", question:"The CFO was praised _____ her ability to reduce costs without layoffs.", options:["for","at","by","in"], answer:0, explanation:"'Praised for' = được khen vì điều gì đó." },
    { id:"ex-pp-14", type:"prepositions", question:"All travel expenses must be approved _____ advance by your manager.", options:["in","on","at","by"], answer:0, explanation:"'In advance' = trước." },
    { id:"ex-pp-15", type:"prepositions", question:"The new tax regulations will come _____ effect next January.", options:["into","onto","on","in"], answer:0, explanation:"'Come into effect' = có hiệu lực." },
    { id:"ex-pp-16", type:"prepositions", question:"The accountant specializes _____ corporate tax planning.", options:["in","on","for","at"], answer:0, explanation:"'Specializes in' = chuyên về." },
    { id:"ex-pp-17", type:"prepositions", question:"The quarterly earnings fell short _____ market expectations.", options:["of","from","in","off"], answer:0, explanation:"'Fall short of' = không đạt được." },
    { id:"ex-pp-18", type:"prepositions", question:"The firm operates _____ strict compliance with financial regulations.", options:["in","on","at","by"], answer:0, explanation:"'In compliance with' = tuân thủ theo." },
    { id:"ex-pp-19", type:"prepositions", question:"Capital gains taxes apply _____ profits from asset sales.", options:["to","on","for","at"], answer:0, explanation:"'Apply to' = áp dụng cho." },
    { id:"ex-pp-20", type:"prepositions", question:"The merger was completed _____ record time, surprising industry analysts.", options:["in","at","by","on"], answer:0, explanation:"'In record time' = trong thời gian kỷ lục." },

    // ──────────────────────────────────────────────
    // CONJUNCTION (Unit 6 – Tech & Innovation)
    // ──────────────────────────────────────────────
    { id:"ex-cj-01", type:"conjunction", question:"The new software is user-friendly, _____ it requires a steep learning curve initially.", options:["but","so","because","although"], answer:0, explanation:"Hai vế tương phản → 'but'." },
    { id:"ex-cj-02", type:"conjunction", question:"_____ the system was updated, response times improved significantly.", options:["Once","While","Unless","Despite"], answer:0, explanation:"'Once' = ngay sau khi, thể hiện kết quả sau hành động." },
    { id:"ex-cj-03", type:"conjunction", question:"The software can be customized _____ it meets each client's specific needs.", options:["so that","provided that","even though","in spite of"], answer:0, explanation:"'So that' = để mà, diễn tả mục đích." },
    { id:"ex-cj-04", type:"conjunction", question:"_____ the data is backed up regularly, there is no risk of permanent loss.", options:["As long as","Even though","Although","Despite"], answer:0, explanation:"'As long as' = miễn là, điều kiện." },
    { id:"ex-cj-05", type:"conjunction", question:"The tech team worked overnight _____ they could deliver the update on time.", options:["so that","despite","however","although"], answer:0, explanation:"'So that' = mục đích." },
    { id:"ex-cj-06", type:"conjunction", question:"We will adopt the new system _____ the costs are justified by efficiency gains.", options:["provided that","in spite of","whereas","because of"], answer:0, explanation:"'Provided that' = với điều kiện là." },
    { id:"ex-cj-07", type:"conjunction", question:"The app was praised for its design _____ users reported some performance issues.", options:["although","so","because","therefore"], answer:0, explanation:"'Although' = mặc dù, tương phản." },
    { id:"ex-cj-08", type:"conjunction", question:"_____ AI tools have become common, many companies still lack the skills to use them.", options:["Although","Because","Since","So"], answer:0, explanation:"'Although' mở đầu mệnh đề nhượng bộ." },
    { id:"ex-cj-09", type:"conjunction", question:"You can upgrade your subscription _____ contact our sales team for a custom plan.", options:["or","nor","but","yet"], answer:0, explanation:"Hai lựa chọn ngang bằng nhau → 'or'." },
    { id:"ex-cj-10", type:"conjunction", question:"The update was released _____ several bugs had been fixed by the engineering team.", options:["after","before","while","unless"], answer:0, explanation:"'After' diễn tả thứ tự thời gian." },
    { id:"ex-cj-11", type:"conjunction", question:"The system crashed _____ the team had just saved all their work.", options:["just as","in case","so that","even so"], answer:0, explanation:"'Just as' = ngay khi, đúng lúc." },
    { id:"ex-cj-12", type:"conjunction", question:"_____ being expensive, the new server significantly improved processing speed.", options:["Despite","Although","However","Whereas"], answer:0, explanation:"'Despite' + gerund/noun phrase = mặc dù." },
    { id:"ex-cj-13", type:"conjunction", question:"The engineers tested the prototype _____ it was approved for mass production.", options:["before","after","because","unless"], answer:0, explanation:"'Before' = trước khi." },
    { id:"ex-cj-14", type:"conjunction", question:"_____ the internet connection is stable, video conferences run smoothly.", options:["When","Before","Unless","Despite"], answer:0, explanation:"'When' = khi, điều kiện luôn đúng." },
    { id:"ex-cj-15", type:"conjunction", question:"The startup attracted investors _____ its innovative approach to data security.", options:["because of","in spite of","so that","whereas"], answer:0, explanation:"'Because of' + noun phrase = nguyên nhân." },
    { id:"ex-cj-16", type:"conjunction", question:"The platform is intuitive _____ first-time users can navigate it easily.", options:["so","so that","because","though"], answer:0, explanation:"'So' = kết quả; 'so that' = mục đích. Ở đây cần 'so' (kết quả)." },
    { id:"ex-cj-17", type:"conjunction", question:"The team finished the project on time _____ they faced many technical obstacles.", options:["even though","so that","because","since"], answer:0, explanation:"'Even though' = mặc dù (nhấn mạnh hơn 'although')." },
    { id:"ex-cj-18", type:"conjunction", question:"Please update the drivers _____ connecting the external devices.", options:["before","after","while","because"], answer:0, explanation:"'Before' + gerund = trước khi làm gì." },
    { id:"ex-cj-19", type:"conjunction", question:"_____ her team works efficiently, they rarely need overtime.", options:["Since","If","Unless","While"], answer:0, explanation:"'Since' = vì, lý do." },
    { id:"ex-cj-20", type:"conjunction", question:"The developer fixed the issue _____ the client's feedback arrived.", options:["as soon as","in order to","despite","whereas"], answer:0, explanation:"'As soon as' = ngay khi." },

    // ──────────────────────────────────────────────
    // PRONOUN (Unit 7 – Manufacturing & QC)
    // ──────────────────────────────────────────────
    { id:"ex-pr-01", type:"pronoun", question:"Each department must submit _____ budget proposal by Friday.", options:["its","their","they","it's"], answer:0, explanation:"'Each department' = số ít → sở hữu cách 'its'." },
    { id:"ex-pr-02", type:"pronoun", question:"The production team exceeded _____ targets for the third consecutive quarter.", options:["its","their","them","it"], answer:1, explanation:"'The production team' trong ngữ cảnh nhóm người → 'their'." },
    { id:"ex-pr-03", type:"pronoun", question:"Neither the supervisor nor the workers have completed _____ safety training.", options:["their","its","them","his"], answer:0, explanation:"'Neither...nor' → động từ chia theo danh từ gần nhất (workers - số nhiều) → 'their'." },
    { id:"ex-pr-04", type:"pronoun", question:"The quality control team conducted _____ inspection before the products were shipped.", options:["its","their","them","itself"], answer:0, explanation:"'The quality control team' = tập thể số ít → 'its'." },
    { id:"ex-pr-05", type:"pronoun", question:"The manager asked everyone to bring _____ ID to the security briefing.", options:["their","its","them","his"], answer:0, explanation:"'Everyone' → đại từ 'their' (trung tính, số nhiều theo nghĩa)." },
    { id:"ex-pr-06", type:"pronoun", question:"The factory workers are proud of _____ ability to maintain high standards.", options:["their","its","they","themselves"], answer:0, explanation:"Chủ ngữ 'workers' → sở hữu cách 'their'." },
    { id:"ex-pr-07", type:"pronoun", question:"The CEO _____ reviewed the quality report before presenting it to the board.", options:["himself","herself","itself","themselves"], answer:0, explanation:"'The CEO' (male) → đại từ phản thân 'himself' nhấn mạnh." },
    { id:"ex-pr-08", type:"pronoun", question:"The new machinery installed _____ without any assistance from outside technicians.", options:["itself","themselves","himself","ourselves"], answer:0, explanation:"'Machinery' là vật → đại từ phản thân 'itself'." },
    { id:"ex-pr-09", type:"pronoun", question:"The plant manager and _____ team worked overtime to meet the order.", options:["his","its","their","them"], answer:0, explanation:"'The plant manager' (người) → 'his team'." },
    { id:"ex-pr-10", type:"pronoun", question:"Every employee is expected to follow _____ designated safety procedures.", options:["their","its","them","he"], answer:0, explanation:"'Every employee' → đại từ trung tính 'their'." },
    { id:"ex-pr-11", type:"pronoun", question:"The assembly line workers exceeded _____ daily quota by 20%.", options:["their","its","them","it"], answer:0, explanation:"Chủ ngữ số nhiều 'workers' → 'their'." },
    { id:"ex-pr-12", type:"pronoun", question:"The manufacturer guarantees that _____ products meet international quality standards.", options:["its","their","it","themselves"], answer:0, explanation:"'The manufacturer' (tổ chức số ít) → 'its'." },
    { id:"ex-pr-13", type:"pronoun", question:"After the product recall, the company re-evaluated _____ entire supply chain.", options:["its","their","them","itself"], answer:0, explanation:"'The company' = tổ chức số ít → 'its'." },
    { id:"ex-pr-14", type:"pronoun", question:"Both the inspector and the technician submitted _____ findings to management.", options:["their","its","them","his"], answer:0, explanation:"'Both...and' + chủ ngữ số nhiều → 'their'." },
    { id:"ex-pr-15", type:"pronoun", question:"The maintenance crew serviced the machines by _____.", options:["themselves","itself","himself","themselves"], answer:0, explanation:"'Crew' (nhóm người) → 'themselves'." },
    { id:"ex-pr-16", type:"pronoun", question:"The defect was discovered during _____ routine inspection.", options:["a","its","their","the"], answer:0, explanation:"'A routine inspection' = mạo từ không xác định." },
    { id:"ex-pr-17", type:"pronoun", question:"If anyone notices a safety hazard, _____ should report it immediately.", options:["they","he","it","them"], answer:0, explanation:"'Anyone' → đại từ trung tính số ít/nhiều 'they'." },
    { id:"ex-pr-18", type:"pronoun", question:"The production supervisor and her assistant updated _____ records.", options:["their","its","them","his"], answer:0, explanation:"Hai chủ ngữ → 'their'." },
    { id:"ex-pr-19", type:"pronoun", question:"The quality report speaks for _____, showing clear evidence of improvement.", options:["itself","themselves","himself","ourselves"], answer:0, explanation:"'The report' (vật) → đại từ phản thân 'itself'." },
    { id:"ex-pr-20", type:"pronoun", question:"One of the managers presented _____ findings at the industry conference.", options:["his","their","its","them"], answer:0, explanation:"'One of the managers' → số ít, thường dùng 'his/her'." },

    // ──────────────────────────────────────────────
    // RELATIVE-CLAUSE (Unit 8 – Travel & Tourism)
    // ──────────────────────────────────────────────
    { id:"ex-rc-01", type:"relative-clause", question:"The hotel _____ we stayed during the conference was fully booked for next month.", options:["where","which","who","whom"], answer:0, explanation:"'Hotel' là nơi chốn → mệnh đề quan hệ nơi chốn dùng 'where'." },
    { id:"ex-rc-02", type:"relative-clause", question:"The travel agent _____ booked our flights has years of experience.", options:["who","which","where","whose"], answer:0, explanation:"'Travel agent' là người → dùng 'who'." },
    { id:"ex-rc-03", type:"relative-clause", question:"The itinerary _____ was sent to all participants included a city tour.", options:["that","who","where","whom"], answer:0, explanation:"'Itinerary' là vật → dùng 'that' hoặc 'which'." },
    { id:"ex-rc-04", type:"relative-clause", question:"We chose a resort _____ facilities include a spa and two swimming pools.", options:["whose","which","that","where"], answer:0, explanation:"Mệnh đề quan hệ sở hữu → 'whose'." },
    { id:"ex-rc-05", type:"relative-clause", question:"The tour guide, _____ spoke four languages, impressed all the visitors.", options:["who","which","whose","that"], answer:0, explanation:"'Tour guide' là người, đây là mệnh đề giải thích → 'who'." },
    { id:"ex-rc-06", type:"relative-clause", question:"The airline _____ we frequently use offers a generous loyalty program.", options:["that","who","whose","whom"], answer:0, explanation:"'Airline' là tổ chức → dùng 'that' hoặc 'which'." },
    { id:"ex-rc-07", type:"relative-clause", question:"This is the city _____ the international tourism summit will be held.", options:["where","which","that","who"], answer:0, explanation:"'City' là nơi chốn → 'where'." },
    { id:"ex-rc-08", type:"relative-clause", question:"The conference room _____ the delegates gathered was equipped with modern technology.", options:["where","which","who","that"], answer:0, explanation:"Nơi chốn → 'where'." },
    { id:"ex-rc-09", type:"relative-clause", question:"The passenger _____ luggage was lost filed a complaint with the airline.", options:["whose","who","which","that"], answer:0, explanation:"Sở hữu → 'whose'." },
    { id:"ex-rc-10", type:"relative-clause", question:"The company hires travel consultants _____ have extensive knowledge of Asian destinations.", options:["who","which","whose","where"], answer:0, explanation:"'Consultants' là người → 'who'." },
    { id:"ex-rc-11", type:"relative-clause", question:"The package tour, _____ includes accommodation and meals, is very popular.", options:["which","who","that","whose"], answer:0, explanation:"Mệnh đề giải thích về vật → 'which'." },
    { id:"ex-rc-12", type:"relative-clause", question:"The travelers _____ booked early received significant discounts.", options:["who","which","whose","where"], answer:0, explanation:"'Travelers' là người → 'who'." },
    { id:"ex-rc-13", type:"relative-clause", question:"The destination _____ she had always wanted to visit was finally within reach.", options:["that","who","whom","where"], answer:0, explanation:"Vật → 'that'." },
    { id:"ex-rc-14", type:"relative-clause", question:"The visa _____ he applied for took three weeks to process.", options:["that","who","whose","where"], answer:0, explanation:"Vật + giới từ → 'that'." },
    { id:"ex-rc-15", type:"relative-clause", question:"The travel blogger, _____ readers number in the millions, launched a travel app.", options:["whose","who","which","whom"], answer:0, explanation:"Sở hữu → 'whose'." },
    { id:"ex-rc-16", type:"relative-clause", question:"I remember the year _____ our company launched its international travel division.", options:["when","where","which","who"], answer:0, explanation:"'Year' = thời gian → mệnh đề quan hệ thời gian dùng 'when'." },
    { id:"ex-rc-17", type:"relative-clause", question:"The hotel manager, to _____ we addressed our concerns, resolved the issue quickly.", options:["whom","who","which","that"], answer:0, explanation:"Giới từ 'to' + đại từ chỉ người → 'whom'." },
    { id:"ex-rc-18", type:"relative-clause", question:"The airport, _____ construction was completed last year, handles 30 million passengers annually.", options:["whose","which","where","that"], answer:0, explanation:"Sở hữu về vật → 'whose'." },
    { id:"ex-rc-19", type:"relative-clause", question:"This is the reason _____ many tourists prefer guided tours over independent travel.", options:["why","when","which","where"], answer:0, explanation:"'Reason' → mệnh đề quan hệ lý do dùng 'why'." },
    { id:"ex-rc-20", type:"relative-clause", question:"The travel agency _____ handles our corporate accounts is based in Singapore.", options:["that","who","whom","when"], answer:0, explanation:"Tổ chức → 'that' hoặc 'which'." },

    // ──────────────────────────────────────────────
    // MODAL (Unit 9 – Corporate Events)
    // ──────────────────────────────────────────────
    { id:"ex-md-01", type:"modal", question:"All conference attendees _____ register in advance to secure their seats.", options:["must","might","could","would"], answer:0, explanation:"Nghĩa bắt buộc → 'must'." },
    { id:"ex-md-02", type:"modal", question:"The annual gala _____ be postponed due to the venue renovation.", options:["might","must","shall","should"], answer:0, explanation:"'Might' = khả năng có thể xảy ra." },
    { id:"ex-md-03", type:"modal", question:"Guests _____ dress formally for the awards ceremony.", options:["should","might","could","would"], answer:0, explanation:"'Should' = lời khuyên/yêu cầu." },
    { id:"ex-md-04", type:"modal", question:"The catering company _____ accommodate dietary restrictions if informed in advance.", options:["can","must","would","shall"], answer:0, explanation:"'Can' = khả năng." },
    { id:"ex-md-05", type:"modal", question:"You _____ use the company shuttle if you don't want to drive.", options:["may","must","shall","need"], answer:0, explanation:"'May' = cho phép." },
    { id:"ex-md-06", type:"modal", question:"The keynote speaker _____ have arrived by now — her flight landed an hour ago.", options:["should","might","must","would"], answer:2, explanation:"'Must have + past participle' = suy luận chắc chắn về quá khứ." },
    { id:"ex-md-07", type:"modal", question:"Participants _____ leave before the closing ceremony to receive their certificates.", options:["must not","might not","could not","should not"], answer:3, explanation:"'Should not' = không nên (lời khuyên)." },
    { id:"ex-md-08", type:"modal", question:"The event coordinator _____ have overlooked the seating arrangement, as some guests are standing.", options:["must","might","should","would"], answer:0, explanation:"'Must have + past participle' = suy luận mạnh." },
    { id:"ex-md-09", type:"modal", question:"If you wish to make a speech, you _____ notify the MC at least 30 minutes beforehand.", options:["should","might","can","shall"], answer:0, explanation:"'Should' = nên, đề xuất." },
    { id:"ex-md-10", type:"modal", question:"The venue _____ hold up to 500 people comfortably.", options:["can","must","should","shall"], answer:0, explanation:"'Can' = khả năng chứa." },
    { id:"ex-md-11", type:"modal", question:"Attendees _____ have pre-registered, but walk-ins are welcome.", options:["need not","must not","should not","cannot"], answer:0, explanation:"'Need not' = không cần thiết." },
    { id:"ex-md-12", type:"modal", question:"Speakers _____ limit their presentations to 20 minutes.", options:["must","might","could","shall"], answer:0, explanation:"Quy định → 'must'." },
    { id:"ex-md-13", type:"modal", question:"The next corporate summit _____ take place in either Tokyo or Seoul.", options:["may","shall","must","need"], answer:0, explanation:"'May' = khả năng, chưa chắc chắn." },
    { id:"ex-md-14", type:"modal", question:"Children under 12 _____ attend the evening gala without a guardian.", options:["may not","might not","should not","need not"], answer:0, explanation:"'May not' = không được phép." },
    { id:"ex-md-15", type:"modal", question:"The organizers _____ have informed us about the change in venue earlier.", options:["should","must","might","could"], answer:0, explanation:"'Should have' = đáng lẽ đã phải (phê bình về quá khứ)." },
    { id:"ex-md-16", type:"modal", question:"Photography _____ only be taken in designated areas during the ceremony.", options:["may","must","will","should"], answer:0, explanation:"'May only' = chỉ được phép." },
    { id:"ex-md-17", type:"modal", question:"The opening remarks _____ last about ten minutes according to the agenda.", options:["should","must","will","can"], answer:2, explanation:"'Will' = dự kiến chắc chắn theo kế hoạch." },
    { id:"ex-md-18", type:"modal", question:"We _____ not use mobile phones during the presentation, as it is distracting.", options:["should","must","might","can"], answer:0, explanation:"'Should not' = không nên." },
    { id:"ex-md-19", type:"modal", question:"The venue reservation _____ be canceled without a fee if done 48 hours before the event.", options:["can","must","should","will"], answer:0, explanation:"'Can' = khả năng/điều kiện có thể." },
    { id:"ex-md-20", type:"modal", question:"The project team _____ have completed the event setup by midnight if they had started earlier.", options:["could","should","might","would"], answer:0, explanation:"'Could have' = lẽ ra có thể (điều kiện loại 3)." },

    // ──────────────────────────────────────────────
    // GERUND-INFINITIVE (Unit 10 – Customer Service)
    // ──────────────────────────────────────────────
    { id:"ex-gi-01", type:"gerund-infinitive", question:"The company stopped _____ its customers with automated responses.", options:["to respond","responding","responded","respond"], answer:1, explanation:"'Stop + gerund' = dừng hành động. 'Stop to do' = dừng để làm việc khác." },
    { id:"ex-gi-02", type:"gerund-infinitive", question:"We recommend _____ customer feedback forms after every service interaction.", options:["to complete","completing","completed","complete"], answer:1, explanation:"'Recommend + gerund' = đề nghị." },
    { id:"ex-gi-03", type:"gerund-infinitive", question:"The service team tried _____ all complaints within 24 hours.", options:["resolving","to resolve","resolve","resolved"], answer:1, explanation:"'Try to do' = cố gắng đạt mục đích." },
    { id:"ex-gi-04", type:"gerund-infinitive", question:"Staff members are trained _____ customer inquiries professionally.", options:["handling","handle","to handle","having handled"], answer:2, explanation:"'Trained to do' = được đào tạo để làm gì." },
    { id:"ex-gi-05", type:"gerund-infinitive", question:"The policy requires all agents _____ their conversations with customers.", options:["to document","documenting","document","documented"], answer:0, explanation:"'Require + object + to do'." },
    { id:"ex-gi-06", type:"gerund-infinitive", question:"Customers appreciate _____ quick responses to their queries.", options:["to receive","receiving","received","receive"], answer:1, explanation:"'Appreciate + gerund'." },
    { id:"ex-gi-07", type:"gerund-infinitive", question:"The manager allowed the team _____ flexible breaks to reduce stress.", options:["taking","take","to take","taken"], answer:2, explanation:"'Allow + object + to do'." },
    { id:"ex-gi-08", type:"gerund-infinitive", question:"She considered _____ to a different department after the restructuring.", options:["to transfer","transfer","transferring","transferred"], answer:2, explanation:"'Consider + gerund'." },
    { id:"ex-gi-09", type:"gerund-infinitive", question:"The supervisor reminded her team _____ client data securely.", options:["storing","to store","store","stored"], answer:1, explanation:"'Remind + object + to do'." },
    { id:"ex-gi-10", type:"gerund-infinitive", question:"They regretted _____ the customer's complaint without proper investigation.", options:["to dismiss","dismiss","dismissing","dismissed"], answer:2, explanation:"'Regret + gerund' = hối tiếc về điều đã làm." },
    { id:"ex-gi-11", type:"gerund-infinitive", question:"The company is committed to _____ its customer satisfaction scores.", options:["improve","improving","improved","improvement"], answer:1, explanation:"'Committed to + gerund'." },
    { id:"ex-gi-12", type:"gerund-infinitive", question:"He forgot _____ the refund, causing the customer additional delays.", options:["processing","processed","to process","process"], answer:2, explanation:"'Forget to do' = quên mất việc phải làm." },
    { id:"ex-gi-13", type:"gerund-infinitive", question:"The agent was determined _____ the issue before the end of his shift.", options:["resolving","resolved","to resolve","resolve"], answer:2, explanation:"'Determined to do'." },
    { id:"ex-gi-14", type:"gerund-infinitive", question:"The team practiced _____ de-escalation techniques in a workshop.", options:["to use","use","using","used"], answer:2, explanation:"'Practice + gerund'." },
    { id:"ex-gi-15", type:"gerund-infinitive", question:"The company decided _____ a new chatbot to handle after-hours inquiries.", options:["implementing","implemented","to implement","implement"], answer:2, explanation:"'Decide to do'." },
    { id:"ex-gi-16", type:"gerund-infinitive", question:"The client seemed _____ with the resolution provided by the support team.", options:["satisfied","to satisfy","satisfying","satisfy"], answer:0, explanation:"'Seem + adjective'." },
    { id:"ex-gi-17", type:"gerund-infinitive", question:"We avoid _____ customers on hold for more than two minutes.", options:["to put","put","putting","puts"], answer:2, explanation:"'Avoid + gerund'." },
    { id:"ex-gi-18", type:"gerund-infinitive", question:"The supervisor encouraged her team _____ proactive in anticipating customer needs.", options:["to be","being","be","been"], answer:0, explanation:"'Encourage + object + to do'." },
    { id:"ex-gi-19", type:"gerund-infinitive", question:"The new hire struggled _____ with the volume of incoming calls.", options:["to cope","cope","coping","coped"], answer:0, explanation:"'Struggle to do'." },
    { id:"ex-gi-20", type:"gerund-infinitive", question:"After _____ the feedback, management decided to revise the service policy.", options:["reviewing","review","reviewed","to review"], answer:0, explanation:"'After + gerund'." },

    // ──────────────────────────────────────────────
    // COMPARISON (Unit 11 – Logistics)
    // ──────────────────────────────────────────────
    { id:"ex-cm-01", type:"comparison", question:"This shipping route is _____ the one we used last quarter.", options:["more efficient than","efficient than","the most efficient","more efficient"], answer:0, explanation:"So sánh hơn hai vế → 'more + adj + than'." },
    { id:"ex-cm-02", type:"comparison", question:"The delivery time using air freight is _____ in the entire logistics network.", options:["the shortest","shorter than","short","as short as"], answer:0, explanation:"So sánh nhất → 'the + superlative'." },
    { id:"ex-cm-03", type:"comparison", question:"Our warehouse is twice _____ the competitor's facility.", options:["as large as","larger than","the largest","more large"], answer:0, explanation:"'Twice as large as' = lớn gấp đôi." },
    { id:"ex-cm-04", type:"comparison", question:"The new logistics software processes orders _____ than the old system.", options:["faster","the fastest","more fast","most fast"], answer:0, explanation:"Trạng từ so sánh hơn: 'faster'." },
    { id:"ex-cm-05", type:"comparison", question:"Ground shipping is _____ expensive than air freight, but it takes longer.", options:["less","fewer","little","least"], answer:0, explanation:"'Less + adjective + than' = ít...hơn." },
    { id:"ex-cm-06", type:"comparison", question:"The _____ a package weighs, the higher the shipping cost.", options:["heavier","heavy","heaviest","more heavy"], answer:0, explanation:"'The + comparative, the + comparative' cấu trúc song song." },
    { id:"ex-cm-07", type:"comparison", question:"This cargo ship can carry _____ containers than the previous model.", options:["more","most","much","many"], answer:0, explanation:"So sánh hơn với danh từ đếm được → 'more'." },
    { id:"ex-cm-08", type:"comparison", question:"The new tracking system is _____ as reliable as the old one.", options:["twice","not","as much","more"], answer:1, explanation:"'Not as reliable as' = kém tin cậy hơn." },
    { id:"ex-cm-09", type:"comparison", question:"Express delivery is _____ option for urgent shipments.", options:["the best","best","better","as good as"], answer:0, explanation:"'The best' = so sánh nhất." },
    { id:"ex-cm-10", type:"comparison", question:"Fuel costs are _____ than expected this month, reducing overall profit margins.", options:["higher","highest","high","more high"], answer:0, explanation:"So sánh hơn: 'higher than'." },
    { id:"ex-cm-11", type:"comparison", question:"The warehouse in Region B has _____ storage capacity than the one in Region A.", options:["greater","greatest","great","more greater"], answer:0, explanation:"So sánh hơn một âm tiết: 'greater than'." },
    { id:"ex-cm-12", type:"comparison", question:"Our fleet of trucks is _____ modern in the entire region.", options:["the most","more","most","the more"], answer:0, explanation:"'The most + adjective' = so sánh nhất." },
    { id:"ex-cm-13", type:"comparison", question:"The customs clearance process is now _____ than it was two years ago.", options:["much faster","much fastest","more faster","the fastest"], answer:0, explanation:"'Much faster' = nhanh hơn nhiều (dùng 'much' để nhấn mạnh so sánh hơn)." },
    { id:"ex-cm-14", type:"comparison", question:"Order accuracy is _____ important factor in customer retention.", options:["the most","the more","more","most"], answer:0, explanation:"So sánh nhất: 'the most important'." },
    { id:"ex-cm-15", type:"comparison", question:"The sea freight option is not _____ fast as air freight, but it is more economical.", options:["as","so","that","too"], answer:0, explanation:"'Not as + adj + as' = so sánh bằng phủ định." },
    { id:"ex-cm-16", type:"comparison", question:"Inventory turnover in Q3 was _____ than in Q2, indicating improved efficiency.", options:["higher","highest","more high","the highest"], answer:0, explanation:"So sánh hơn." },
    { id:"ex-cm-17", type:"comparison", question:"The _____ efficient the route, the lower the fuel consumption.", options:["more","most","much","less"], answer:0, explanation:"'The more + adj, the + comparative'." },
    { id:"ex-cm-18", type:"comparison", question:"Same-day delivery is _____ option, but it is the most popular with customers.", options:["the costliest","costliest","more costly","as costly as"], answer:0, explanation:"'The + superlative'." },
    { id:"ex-cm-19", type:"comparison", question:"The new cargo vessels are _____ fuel-efficient than the older models.", options:["significantly more","significant more","significanlty most","more significant"], answer:0, explanation:"'Significantly more + adj + than'." },
    { id:"ex-cm-20", type:"comparison", question:"Processing time for international shipments is _____ longer than for domestic ones.", options:["considerably","consider","considerable","consideration"], answer:0, explanation:"Trạng từ 'considerably' bổ nghĩa so sánh hơn." },

    // ──────────────────────────────────────────────
    // PARTICIPLES (Unit 12 – Health & Safety)
    // ──────────────────────────────────────────────
    { id:"ex-pt-01", type:"participles", question:"_____ in bright yellow, the safety vests are visible from a distance.", options:["Colored","Coloring","Having colored","To color"], answer:0, explanation:"Past participle trong mệnh đề rút gọn bị động." },
    { id:"ex-pt-02", type:"participles", question:"The worker, _____ the safety manual, knew exactly what to do in an emergency.", options:["having read","reads","reading","read"], answer:0, explanation:"'Having + past participle' diễn tả hành động hoàn thành trước." },
    { id:"ex-pt-03", type:"participles", question:"_____ the proper procedures, employees can avoid most workplace accidents.", options:["Following","Followed","To follow","Having followed"], answer:0, explanation:"Hiện tại phân từ ở đầu câu: chủ ngữ chính làm hành động đó." },
    { id:"ex-pt-04", type:"participles", question:"The equipment, _____ regularly, showed no signs of wear.", options:["maintained","maintaining","to maintain","having maintaining"], answer:0, explanation:"Past participle trong mệnh đề rút gọn bị động." },
    { id:"ex-pt-05", type:"participles", question:"_____ by the sudden alarm, the workers evacuated the building immediately.", options:["Startled","Startling","To startle","Having startled"], answer:0, explanation:"Past participle mang nghĩa bị động + trạng thái." },
    { id:"ex-pt-06", type:"participles", question:"The chemicals, _____ as hazardous, must be stored separately.", options:["classified","classifying","to classify","classify"], answer:0, explanation:"Past participle trong mệnh đề rút gọn." },
    { id:"ex-pt-07", type:"participles", question:"_____ the risk assessment, the safety officer found several potential hazards.", options:["Conducting","Having conducted","Conducted","To conduct"], answer:1, explanation:"'Having conducted' = sau khi đã hoàn thành việc kiểm tra." },
    { id:"ex-pt-08", type:"participles", question:"The report _____ the incident clearly outlined all contributing factors.", options:["describing","described","to describe","describe"], answer:0, explanation:"Hiện tại phân từ bổ nghĩa cho danh từ 'report' (đang mô tả)." },
    { id:"ex-pt-09", type:"participles", question:"All equipment, _____ at regular intervals, is less likely to malfunction.", options:["inspected","inspecting","to inspect","inspect"], answer:0, explanation:"Past participle mang nghĩa bị động." },
    { id:"ex-pt-10", type:"participles", question:"_____ in protective gear, the staff entered the contaminated area.", options:["Dressed","Dressing","To dress","Having dressing"], answer:0, explanation:"Past participle = đã mặc vào (trạng thái)." },
    { id:"ex-pt-11", type:"participles", question:"The new safety protocol, _____ last month, has already reduced accident rates.", options:["introduced","introducing","introduce","having introduce"], answer:0, explanation:"Past participle trong mệnh đề rút gọn bị động." },
    { id:"ex-pt-12", type:"participles", question:"_____ the forklift all day, the operator needed a break.", options:["Having operated","Operated","Operate","Operating"], answer:0, explanation:"'Having operated' = sau khi đã lái cả ngày." },
    { id:"ex-pt-13", type:"participles", question:"The manual _____ to all staff covers emergency procedures in detail.", options:["distributed","distributing","to distribute","distribute"], answer:0, explanation:"Past participle bổ nghĩa cho 'manual' (đã được phân phát)." },
    { id:"ex-pt-14", type:"participles", question:"_____ through a residential area, drivers must follow reduced speed limits.", options:["Passing","Passed","Having passed","To pass"], answer:0, explanation:"Hiện tại phân từ = khi đang đi qua." },
    { id:"ex-pt-15", type:"participles", question:"The workers _____ safely wore helmets and high-visibility vests at all times.", options:["working","worked","to work","having work"], answer:0, explanation:"Hiện tại phân từ bổ nghĩa cho 'workers'." },
    { id:"ex-pt-16", type:"participles", question:"_____ the spill immediately, the crew prevented further contamination.", options:["Containing","Contained","Having contained","To contain"], answer:2, explanation:"'Having contained' = sau khi đã ngăn chặn." },
    { id:"ex-pt-17", type:"participles", question:"The ladder, _____ incorrectly, caused the worker to fall.", options:["positioned","positioning","to position","having positioned"], answer:0, explanation:"Past participle mô tả tình trạng của thang." },
    { id:"ex-pt-18", type:"participles", question:"_____ with the correct PPE, workers can handle hazardous materials safely.", options:["Equipped","Equipping","To equip","Being equip"], answer:0, explanation:"Past participle = được trang bị (bị động)." },
    { id:"ex-pt-19", type:"participles", question:"The safety trainer, _____ in first aid, led the emergency drill.", options:["certified","certifying","to certify","certifies"], answer:0, explanation:"Past participle bổ nghĩa cho 'trainer'." },
    { id:"ex-pt-20", type:"participles", question:"_____ the fire extinguisher, the employee quickly controlled the small blaze.", options:["Grabbing","Grabbed","Having grabbed","To grab"], answer:0, explanation:"Hiện tại phân từ: hành động xảy ra cùng lúc." },

    // ──────────────────────────────────────────────
    // SUBJECT-VERB AGREEMENT (Unit 13 – Banking)
    // ──────────────────────────────────────────────
    { id:"ex-sv-01", type:"subject-verb", question:"Neither the loan officer nor the branch managers _____ authorized the transaction.", options:["have","has","is","are"], answer:0, explanation:"'Neither...nor' → chia theo danh từ gần nhất (managers - số nhiều) → 'have'." },
    { id:"ex-sv-02", type:"subject-verb", question:"The number of investment accounts _____ increased significantly this year.", options:["has","have","are","were"], answer:0, explanation:"'The number of' = số đơn → 'has'." },
    { id:"ex-sv-03", type:"subject-verb", question:"Each of the financial advisors _____ required to complete certification annually.", options:["is","are","were","have"], answer:0, explanation:"'Each of' + số nhiều → động từ chia số đơn." },
    { id:"ex-sv-04", type:"subject-verb", question:"The board of directors _____ scheduled a meeting to discuss the merger.", options:["has","have","are","were"], answer:0, explanation:"'Board of directors' = tổ chức số ít → 'has'." },
    { id:"ex-sv-05", type:"subject-verb", question:"A number of clients _____ expressed concerns about the new fee structure.", options:["have","has","is","was"], answer:0, explanation:"'A number of' = số nhiều → 'have'." },
    { id:"ex-sv-06", type:"subject-verb", question:"Economics _____ considered a challenging subject by many banking professionals.", options:["is","are","was considered","have been"], answer:0, explanation:"Tên môn học → số ít → 'is'." },
    { id:"ex-sv-07", type:"subject-verb", question:"Both the CEO and the CFO _____ presented at the investor conference.", options:["were","was","is","has"], answer:0, explanation:"'Both...and' → số nhiều → 'were'." },
    { id:"ex-sv-08", type:"subject-verb", question:"The committee _____ divided on the issue of interest rate adjustments.", options:["is","are","was","have"], answer:0, explanation:"'The committee' là tập thể số ít → 'is'." },
    { id:"ex-sv-09", type:"subject-verb", question:"Profits, along with revenue, _____ on the rise this fiscal quarter.", options:["are","is","was","has been"], answer:0, explanation:"Chủ ngữ chính 'Profits' số nhiều → 'are'. Cụm 'along with' không thay đổi số." },
    { id:"ex-sv-10", type:"subject-verb", question:"Twenty percent of the loan portfolio _____ classified as high-risk.", options:["is","are","have","were"], answer:0, explanation:"Phần trăm + danh từ không đếm được → số ít → 'is'." },
    { id:"ex-sv-11", type:"subject-verb", question:"The interest rate that the bank charges _____ competitive compared to peers.", options:["is","are","has","have"], answer:0, explanation:"Chủ ngữ là 'The interest rate' số ít → 'is'." },
    { id:"ex-sv-12", type:"subject-verb", question:"Every branch manager and loan officer _____ received the updated compliance guidelines.", options:["has","have","are","is"], answer:0, explanation:"'Every + noun and noun' → động từ số ít → 'has'." },
    { id:"ex-sv-13", type:"subject-verb", question:"The news about the interest rate hike _____ surprised investors worldwide.", options:["has","have","were","are"], answer:0, explanation:"'News' là danh từ không đếm được → 'has'." },
    { id:"ex-sv-14", type:"subject-verb", question:"Either the account holder or the authorized representative _____ required to sign.", options:["is","are","have","were"], answer:0, explanation:"'Either...or' → chia theo danh từ gần nhất ('representative' số ít) → 'is'." },
    { id:"ex-sv-15", type:"subject-verb", question:"The list of transactions _____ reviewed by the auditor every quarter.", options:["is","are","have","were"], answer:0, explanation:"'The list' số ít → 'is'." },
    { id:"ex-sv-16", type:"subject-verb", question:"None of the loan applications _____ fully processed yet.", options:["have been","has been","is","was"], answer:0, explanation:"'None of' + danh từ số nhiều → thường dùng số nhiều." },
    { id:"ex-sv-17", type:"subject-verb", question:"The team of financial analysts _____ its report every Monday morning.", options:["submits","submit","are submitted","have submitted"], answer:0, explanation:"'The team' số ít → 'submits'." },
    { id:"ex-sv-18", type:"subject-verb", question:"There _____ several discrepancies in the quarterly balance sheet.", options:["are","is","has","were"], answer:0, explanation:"'There are' + danh từ số nhiều." },
    { id:"ex-sv-19", type:"subject-verb", question:"The data from all branches _____ compiled into a single report.", options:["is","are","have","were"], answer:0, explanation:"'The data' → danh từ không đếm được → 'is'." },
    { id:"ex-sv-20", type:"subject-verb", question:"Neither the analyst nor her supervisors _____ aware of the compliance breach.", options:["were","was","is","has"], answer:0, explanation:"'Neither...nor' → gần nhất là 'supervisors' số nhiều → 'were'." },

    // ──────────────────────────────────────────────
    // NOUN-CLAUSES (Unit 14 – Real Estate)
    // ──────────────────────────────────────────────
    { id:"ex-nc-01", type:"noun-clauses", question:"The client asked _____ the property was available for immediate occupancy.", options:["whether","that","what","which"], answer:0, explanation:"Câu hỏi gián tiếp với 'yes/no' → 'whether'." },
    { id:"ex-nc-02", type:"noun-clauses", question:"It is unclear _____ the building will meet the new environmental standards.", options:["whether","what","that","which"], answer:0, explanation:"Mệnh đề danh từ với 'yes/no question' → 'whether'." },
    { id:"ex-nc-03", type:"noun-clauses", question:"The report confirmed _____ renovation costs would exceed the original estimate.", options:["that","what","whether","which"], answer:0, explanation:"'Confirm + that clause'." },
    { id:"ex-nc-04", type:"noun-clauses", question:"We need to determine _____ the land can be rezoned for commercial use.", options:["whether","that","what","how"], answer:0, explanation:"'Determine + whether' = xác định liệu có thể không." },
    { id:"ex-nc-05", type:"noun-clauses", question:"The contract specifies _____ the tenant must notify the landlord 60 days before vacating.", options:["that","what","how","whether"], answer:0, explanation:"'Specifies + that clause' = quy định rằng." },
    { id:"ex-nc-06", type:"noun-clauses", question:"_____ the property will appreciate in value is the key concern for investors.", options:["Whether","What","That","How"], answer:0, explanation:"Mệnh đề danh từ làm chủ ngữ: 'Whether...is...'." },
    { id:"ex-nc-07", type:"noun-clauses", question:"The agent explained _____ the appraisal process typically takes two weeks.", options:["that","what","how","whether"], answer:0, explanation:"'Explained + that clause' = giải thích rằng." },
    { id:"ex-nc-08", type:"noun-clauses", question:"We should consider _____ the offer price reflects current market conditions.", options:["whether","what","how","that"], answer:0, explanation:"'Consider + whether' = xem xét liệu... hay không." },
    { id:"ex-nc-09", type:"noun-clauses", question:"The inspector's report revealed _____ several structural issues needed attention.", options:["that","what","whether","which"], answer:0, explanation:"'Revealed + that clause'." },
    { id:"ex-nc-10", type:"noun-clauses", question:"It remains uncertain _____ interest rates will affect housing demand next year.", options:["how","what","that","which"], answer:0, explanation:"'Uncertain + how clause' = không chắc chắn như thế nào." },
    { id:"ex-nc-11", type:"noun-clauses", question:"The buyer wanted to know _____ the property had any outstanding mortgages.", options:["whether","that","how","what"], answer:0, explanation:"Câu hỏi gián tiếp yes/no → 'whether'." },
    { id:"ex-nc-12", type:"noun-clauses", question:"_____ drives property prices up in urban areas is a combination of demand and limited supply.", options:["What","That","Which","How"], answer:0, explanation:"'What' = điều gì, làm chủ ngữ mệnh đề danh từ." },
    { id:"ex-nc-13", type:"noun-clauses", question:"The lease agreement states _____ all utilities must be paid by the tenant.", options:["that","whether","what","how"], answer:0, explanation:"'States + that clause'." },
    { id:"ex-nc-14", type:"noun-clauses", question:"The city council has not decided _____ to approve the new development plan.", options:["whether","that","what","which"], answer:0, explanation:"'Decided + whether' = quyết định liệu có... không." },
    { id:"ex-nc-15", type:"noun-clauses", question:"Investors are aware _____ market conditions can change rapidly.", options:["that","whether","how","what"], answer:0, explanation:"'Aware + that clause'." },
    { id:"ex-nc-16", type:"noun-clauses", question:"The survey showed _____ most buyers prefer properties in walkable neighborhoods.", options:["that","whether","which","how"], answer:0, explanation:"'Showed + that clause' = cho thấy rằng." },
    { id:"ex-nc-17", type:"noun-clauses", question:"She asked the realtor _____ the price was negotiable.", options:["whether","that","how","which"], answer:0, explanation:"Câu hỏi gián tiếp yes/no → 'whether'." },
    { id:"ex-nc-18", type:"noun-clauses", question:"The reason _____ the deal fell through is still under investigation.", options:["why","that","how","when"], answer:0, explanation:"'The reason + why clause'." },
    { id:"ex-nc-19", type:"noun-clauses", question:"The committee will evaluate _____ the proposed development aligns with zoning laws.", options:["whether","that","how","what"], answer:0, explanation:"'Evaluate + whether'." },
    { id:"ex-nc-20", type:"noun-clauses", question:"He wondered _____ the construction would be completed by the contract date.", options:["whether","that","what","how"], answer:0, explanation:"'Wondered + whether' = tự hỏi liệu... có không." },

    // ──────────────────────────────────────────────
    // ADVERB-TIME (Unit 15 – Media & Communications)
    // ──────────────────────────────────────────────
    { id:"ex-at-01", type:"adverb-time", question:"The press release will be distributed _____ the product launch event begins.", options:["before","after","while","until"], answer:0, explanation:"'Before' = trước khi." },
    { id:"ex-at-02", type:"adverb-time", question:"The journalist filed her story _____ she returned from the press conference.", options:["as soon as","before","until","while"], answer:0, explanation:"'As soon as' = ngay khi." },
    { id:"ex-at-03", type:"adverb-time", question:"The broadcast will remain on air _____ further notice from the station manager.", options:["until","while","as","when"], answer:0, explanation:"'Until further notice' = cho đến khi có thông báo thêm." },
    { id:"ex-at-04", type:"adverb-time", question:"_____ the live interview was airing, the studio received hundreds of viewer messages.", options:["While","After","Until","As soon as"], answer:0, explanation:"'While' = trong khi (hai hành động xảy ra cùng lúc)." },
    { id:"ex-at-05", type:"adverb-time", question:"The editor reviews all articles _____ they are published online.", options:["before","after","while","until"], answer:0, explanation:"'Before' = trước khi xuất bản." },
    { id:"ex-at-06", type:"adverb-time", question:"The news agency will issue a correction _____ the error has been verified.", options:["once","while","until","before"], answer:0, explanation:"'Once' = ngay khi đã xác nhận." },
    { id:"ex-at-07", type:"adverb-time", question:"Please hold all calls _____ the director finishes the press briefing.", options:["until","while","before","since"], answer:0, explanation:"'Until' = cho đến khi." },
    { id:"ex-at-08", type:"adverb-time", question:"The photographer had _____ captured several striking images before the event ended.", options:["already","yet","still","ever"], answer:0, explanation:"'Had already + past participle' = đã... rồi (trước một điểm trong quá khứ)." },
    { id:"ex-at-09", type:"adverb-time", question:"The magazine has _____ published over 500 issues since its launch.", options:["already","yet","still","just"], answer:0, explanation:"'Has already published' = đã xuất bản rồi." },
    { id:"ex-at-10", type:"adverb-time", question:"The documentary was so compelling that viewers _____ stopped watching.", options:["rarely","often","sometimes","usually"], answer:0, explanation:"'Rarely' = hiếm khi, phù hợp với ngữ cảnh." },
    { id:"ex-at-11", type:"adverb-time", question:"The reporter had _____ submitted the story when the deadline was extended.", options:["just","already","yet","still"], answer:0, explanation:"'Had just + past participle' = vừa mới làm xong." },
    { id:"ex-at-12", type:"adverb-time", question:"The network _____ airs breaking news as it happens, 24 hours a day.", options:["always","never","rarely","seldom"], answer:0, explanation:"'Always' = luôn luôn." },
    { id:"ex-at-13", type:"adverb-time", question:"The website traffic spikes _____ major news stories break.", options:["whenever","while","until","before"], answer:0, explanation:"'Whenever' = mỗi khi." },
    { id:"ex-at-14", type:"adverb-time", question:"The digital edition is _____ available before the print version reaches newsstands.", options:["often","never","rarely","seldom"], answer:0, explanation:"'Often' = thường xuyên." },
    { id:"ex-at-15", type:"adverb-time", question:"_____ the merger was announced, shares in both companies surged.", options:["Once","While","Until","Before"], answer:0, explanation:"'Once' = ngay khi, sau đó." },
    { id:"ex-at-16", type:"adverb-time", question:"The editor _____ checks the facts before approving an article.", options:["always","already","yet","still"], answer:0, explanation:"'Always' = luôn luôn (thói quen)." },
    { id:"ex-at-17", type:"adverb-time", question:"We haven't received the interview transcript _____.", options:["yet","already","still","just"], answer:0, explanation:"'Yet' = chưa, dùng cuối câu phủ định." },
    { id:"ex-at-18", type:"adverb-time", question:"The media team is _____ editing the footage for tomorrow's broadcast.", options:["still","already","yet","just"], answer:0, explanation:"'Still' = vẫn đang (tiếp diễn)." },
    { id:"ex-at-19", type:"adverb-time", question:"The editor had _____ approved the layout when the story changed completely.", options:["just","already","yet","still"], answer:0, explanation:"'Had just approved' = vừa mới duyệt xong." },
    { id:"ex-at-20", type:"adverb-time", question:"The station's audience has grown _____ more digital platforms were introduced.", options:["since","while","until","before"], answer:0, explanation:"'Since' = kể từ khi (dùng với Perfect tense)." },

    // ──────────────────────────────────────────────
    // VOCABULARY-CONTEXT (Unit 16 – Retail & E-commerce)
    // ──────────────────────────────────────────────
    { id:"ex-vc-01", type:"vocabulary-context", question:"The store is offering a 20% _____ on all electronics this weekend.", options:["discount","reduction","deduction","rebate"], answer:0, explanation:"'Discount' là từ phổ biến nhất trong bán lẻ cho giảm giá trực tiếp." },
    { id:"ex-vc-02", type:"vocabulary-context", question:"Customers must _____ their purchase within 30 days to receive a full refund.", options:["return","replace","restore","retrieve"], answer:0, explanation:"'Return a purchase' = trả lại hàng." },
    { id:"ex-vc-03", type:"vocabulary-context", question:"The website's checkout process is _____ to navigate, helping reduce cart abandonment.", options:["intuitive","intensive","indicative","incentive"], answer:0, explanation:"'Intuitive' = dễ dùng tự nhiên." },
    { id:"ex-vc-04", type:"vocabulary-context", question:"The online store offers free _____ on orders over $50.", options:["shipping","handling","postage","cargo"], answer:0, explanation:"'Free shipping' = giao hàng miễn phí trong thương mại điện tử." },
    { id:"ex-vc-05", type:"vocabulary-context", question:"The inventory system automatically _____ stock levels when items are sold.", options:["updates","upgrades","uplifts","undertakes"], answer:0, explanation:"'Updates stock levels' = cập nhật tồn kho." },
    { id:"ex-vc-06", type:"vocabulary-context", question:"To increase customer loyalty, the retailer launched an exclusive _____ program.", options:["rewards","award","prizes","bonuses"], answer:0, explanation:"'Rewards program' = chương trình tích điểm khách hàng." },
    { id:"ex-vc-07", type:"vocabulary-context", question:"The company's e-commerce platform saw a significant _____ in traffic during the sale.", options:["surge","search","source","series"], answer:0, explanation:"'Surge in traffic' = tăng đột biến lượng truy cập." },
    { id:"ex-vc-08", type:"vocabulary-context", question:"Shoppers can _____ wish list items and receive alerts when prices drop.", options:["save","store","set","sort"], answer:0, explanation:"'Save items' to a wish list = lưu sản phẩm." },
    { id:"ex-vc-09", type:"vocabulary-context", question:"The retailer _____ its product range to include premium organic goods.", options:["expanded","explored","exceeded","exhibited"], answer:0, explanation:"'Expanded product range' = mở rộng danh mục sản phẩm." },
    { id:"ex-vc-10", type:"vocabulary-context", question:"Customers who _____ by email will be the first to know about upcoming sales.", options:["subscribe","submit","suggest","support"], answer:0, explanation:"'Subscribe by email' = đăng ký nhận email." },
    { id:"ex-vc-11", type:"vocabulary-context", question:"The brand's _____ packaging attracted a lot of attention at trade shows.", options:["distinctive","distributing","distracted","distressing"], answer:0, explanation:"'Distinctive packaging' = bao bì nổi bật, dễ nhận biết." },
    { id:"ex-vc-12", type:"vocabulary-context", question:"The platform uses _____ data to suggest products based on browsing history.", options:["personalized","personal","person","personality"], answer:0, explanation:"'Personalized data' = dữ liệu được cá nhân hóa." },
    { id:"ex-vc-13", type:"vocabulary-context", question:"The retailer _____ excess stock at the end of each season to make room for new arrivals.", options:["clears","closes","cancels","cuts"], answer:0, explanation:"'Clears excess stock' = thanh lý hàng tồn." },
    { id:"ex-vc-14", type:"vocabulary-context", question:"All purchases made online are _____ via a secure payment gateway.", options:["processed","produced","provided","projected"], answer:0, explanation:"'Processed via gateway' = xử lý qua cổng thanh toán." },
    { id:"ex-vc-15", type:"vocabulary-context", question:"The mobile app allows customers to _____ their order status in real time.", options:["track","trial","trace","trust"], answer:0, explanation:"'Track order status' = theo dõi đơn hàng." },
    { id:"ex-vc-16", type:"vocabulary-context", question:"A satisfied customer is more likely to _____ a product to friends and family.", options:["recommend","remand","remind","record"], answer:0, explanation:"'Recommend a product' = giới thiệu sản phẩm." },
    { id:"ex-vc-17", type:"vocabulary-context", question:"The store _____ a price-matching policy to remain competitive.", options:["adopted","adapted","adored","added"], answer:0, explanation:"'Adopted a policy' = áp dụng chính sách." },
    { id:"ex-vc-18", type:"vocabulary-context", question:"Customer _____ is key to long-term business growth in retail.", options:["retention","rotation","relation","reaction"], answer:0, explanation:"'Customer retention' = giữ chân khách hàng." },
    { id:"ex-vc-19", type:"vocabulary-context", question:"The flash sale was a limited-time _____ offering steep discounts.", options:["promotion","procedure","production","proportion"], answer:0, explanation:"'Promotion' = chương trình khuyến mãi." },
    { id:"ex-vc-20", type:"vocabulary-context", question:"The online marketplace _____ thousands of independent sellers from around the world.", options:["hosts","holds","harvests","handles"], answer:0, explanation:"'Hosts sellers' = nền tảng chứa/kết nối nhiều người bán." },

    // ──────────────────────────────────────────────
    // INVERSION (Unit 19 – Law & Contracts)
    // ──────────────────────────────────────────────
    { id:"ex-iv-01", type:"inversion", question:"Not only _____ the contract invalid, but it also contained fraudulent clauses.", options:["was it","it was","is it","it is"], answer:0, explanation:"'Not only' đứng đầu câu → đảo ngữ: Not only + was + S." },
    { id:"ex-iv-02", type:"inversion", question:"Seldom _____ such a complex litigation case handled by a single attorney.", options:["is","was","has been","had been"], answer:0, explanation:"'Seldom' đứng đầu câu → đảo ngữ: Seldom + is + S." },
    { id:"ex-iv-03", type:"inversion", question:"Under no circumstances _____ the confidential terms of this agreement be disclosed.", options:["should","must","shall","are"], answer:2, explanation:"'Under no circumstances' → đảo ngữ: shall (dùng trong văn bản pháp lý)." },
    { id:"ex-iv-04", type:"inversion", question:"Hardly _____ the attorney presented the evidence when the judge called a recess.", options:["had","has","was","is"], answer:0, explanation:"'Hardly...when' → đảo ngữ: Hardly + had + S + past participle." },
    { id:"ex-iv-05", type:"inversion", question:"Only after signing the NDA _____ granted access to the sensitive documents.", options:["were employees","employees were","employees had","had employees"], answer:0, explanation:"'Only after' → đảo ngữ trong mệnh đề chính." },
    { id:"ex-iv-06", type:"inversion", question:"Never before _____ such a severe penalty been imposed for a contract breach.", options:["has","have","was","had"], answer:0, explanation:"'Never before' + Present Perfect → đảo ngữ: has + S." },
    { id:"ex-iv-07", type:"inversion", question:"No sooner _____ the verdict announced than the defendant's lawyers filed an appeal.", options:["had been","was","has been","is"], answer:0, explanation:"'No sooner...than' → Past Perfect đảo ngữ." },
    { id:"ex-iv-08", type:"inversion", question:"Only by reviewing the full contract _____ identify the problematic clause.", options:["could the team","the team could","can the team","the team can"], answer:0, explanation:"'Only by' → đảo ngữ trong mệnh đề chính." },
    { id:"ex-iv-09", type:"inversion", question:"Rarely _____ arbitration result in a decision that satisfies both parties fully.", options:["does","do","has","had"], answer:0, explanation:"'Rarely' + đảo ngữ: does + S." },
    { id:"ex-iv-10", type:"inversion", question:"Not until the clause was amended _____ both parties agree to sign.", options:["did","would","were","have"], answer:0, explanation:"'Not until' → đảo ngữ: did + S + V." },
    { id:"ex-iv-11", type:"inversion", question:"Should any party _____ to fulfill its obligations, penalties will apply immediately.", options:["fail","fails","failed","have failed"], answer:0, explanation:"'Should + S + V' = đảo ngữ điều kiện loại 1 trang trọng." },
    { id:"ex-iv-12", type:"inversion", question:"Were the defendant _____ to comply with the court order, further sanctions would follow.", options:["to refuse","refused","refusing","refuse"], answer:0, explanation:"'Were + S + to V' = đảo ngữ điều kiện loại 2 trang trọng." },
    { id:"ex-iv-13", type:"inversion", question:"Had the company _____ better legal advice, it might have avoided the lawsuit.", options:["sought","seek","seeking","seeks"], answer:0, explanation:"'Had + S + past participle' = đảo ngữ điều kiện loại 3." },
    { id:"ex-iv-14", type:"inversion", question:"At no time _____ employees discuss client information outside the office.", options:["should","would","can","may"], answer:0, explanation:"'At no time' → đảo ngữ: should + S." },
    { id:"ex-iv-15", type:"inversion", question:"Not only _____ the firm liable for damages, but it also faced criminal charges.", options:["was it held","it was held","is it held","it is held"], answer:0, explanation:"'Not only' → đảo ngữ Past Simple." },
    { id:"ex-iv-16", type:"inversion", question:"So _____ the legal implications that the CEO consulted three separate attorneys.", options:["complex were","were complex","complex are","are complex"], answer:0, explanation:"'So + adj + were + S' = đảo ngữ nhấn mạnh." },
    { id:"ex-iv-17", type:"inversion", question:"Little _____ the client realize the clause had significant long-term consequences.", options:["did","does","had","has"], answer:0, explanation:"'Little' (phủ định) + đảo ngữ: did + S." },
    { id:"ex-iv-18", type:"inversion", question:"In no way _____ the company responsible for indirect damages under this agreement.", options:["shall it be","it shall be","it will be","will be it"], answer:0, explanation:"'In no way' → đảo ngữ: shall + S." },
    { id:"ex-iv-19", type:"inversion", question:"Only when the full payment is received _____ the title transfer to the buyer.", options:["will","would","shall","should"], answer:0, explanation:"'Only when' → đảo ngữ: will + S." },
    { id:"ex-iv-20", type:"inversion", question:"Such _____ the pressure from creditors that the company filed for bankruptcy.", options:["was","is","had been","were"], answer:0, explanation:"'Such was + S' = đảo ngữ nhấn mạnh mức độ." },

    // ──────────────────────────────────────────────
    // QUANTIFIERS (Unit 20 – Environment & Energy)
    // ──────────────────────────────────────────────
    { id:"ex-qn-01", type:"quantifiers", question:"_____ companies have adopted renewable energy solutions over the past decade.", options:["Many","Much","A little","Little"], answer:0, explanation:"'Many' = nhiều, dùng với danh từ đếm được số nhiều (companies)." },
    { id:"ex-qn-02", type:"quantifiers", question:"There is _____ evidence supporting the long-term benefits of solar power.", options:["much","many","few","a few"], answer:0, explanation:"'Much' = nhiều, dùng với danh từ không đếm được (evidence)." },
    { id:"ex-qn-03", type:"quantifiers", question:"_____ of the factory's carbon emissions come from its outdated machinery.", options:["Most","Almost","Nearly","Mostly"], answer:0, explanation:"'Most of' = phần lớn trong số." },
    { id:"ex-qn-04", type:"quantifiers", question:"We have _____ time left before the environmental audit begins.", options:["little","few","a few","many"], answer:0, explanation:"'Little' = rất ít, dùng với không đếm được (time), mang nghĩa tiêu cực." },
    { id:"ex-qn-05", type:"quantifiers", question:"_____ regions are still heavily dependent on fossil fuels for electricity.", options:["A number of","A great deal of","An amount of","A level of"], answer:0, explanation:"'A number of' = một số, dùng với danh từ đếm được số nhiều." },
    { id:"ex-qn-06", type:"quantifiers", question:"The company has invested _____ money in developing eco-friendly packaging.", options:["a great deal of","many","a number of","few"], answer:0, explanation:"'A great deal of' = rất nhiều, dùng với không đếm được (money)." },
    { id:"ex-qn-07", type:"quantifiers", question:"_____ of the clean energy projects were completed on time.", options:["Several","A little","Much","A great deal"], answer:0, explanation:"'Several' = một vài, dùng với đếm được số nhiều." },
    { id:"ex-qn-08", type:"quantifiers", question:"There are _____ alternatives to single-use plastic that are commercially viable.", options:["few","little","much","a great deal of"], answer:0, explanation:"'Few' = rất ít, dùng với đếm được, nghĩa tiêu cực." },
    { id:"ex-qn-09", type:"quantifiers", question:"The plant produces _____ waste since the new filtration system was installed.", options:["less","fewer","little","a few"], answer:0, explanation:"'Less' = ít hơn, dùng với không đếm được (waste)." },
    { id:"ex-qn-10", type:"quantifiers", question:"_____ countries have committed to achieving net zero emissions by 2050.", options:["Numerous","Much","A little","A great deal of"], answer:0, explanation:"'Numerous' = rất nhiều, dùng với đếm được số nhiều." },
    { id:"ex-qn-11", type:"quantifiers", question:"The solar farm generates _____ electricity to power the entire city.", options:["enough","many","few","several"], answer:0, explanation:"'Enough' = đủ, có thể dùng với cả đếm được và không đếm được." },
    { id:"ex-qn-12", type:"quantifiers", question:"The NGO has _____ resources to fund all proposed environmental projects.", options:["insufficient","too few","not many","too little"], answer:3, explanation:"'Too little' = quá ít, dùng với không đếm được (resources trong ngữ cảnh này là abstract)." },
    { id:"ex-qn-13", type:"quantifiers", question:"_____ the facilities have been upgraded to use energy-efficient lighting.", options:["All of","All","Every","Each"], answer:0, explanation:"'All of + the + noun' = tất cả các." },
    { id:"ex-qn-14", type:"quantifiers", question:"The company uses _____ recycled materials as possible in its manufacturing process.", options:["as many","as much","so many","so much"], answer:0, explanation:"'As many + countable noun + as possible'." },
    { id:"ex-qn-15", type:"quantifiers", question:"_____ attention has been paid to reducing water consumption in the new design.", options:["Considerable","Many","Few","Several"], answer:0, explanation:"'Considerable' = đáng kể, dùng với không đếm được (attention)." },
    { id:"ex-qn-16", type:"quantifiers", question:"The new regulations have resulted in _____ reduction in industrial pollution.", options:["a significant","significant many","much many","a lot many"], answer:0, explanation:"'A significant reduction' = danh từ đơn số đếm được." },
    { id:"ex-qn-17", type:"quantifiers", question:"Not _____ businesses fully understand the financial benefits of going green.", options:["enough","much","little","fewer"], answer:0, explanation:"'Not enough businesses' = không đủ số lượng doanh nghiệp." },
    { id:"ex-qn-18", type:"quantifiers", question:"The report identified _____ ways to reduce the carbon footprint of the supply chain.", options:["several","much","a great deal of","little"], answer:0, explanation:"'Several' + đếm được số nhiều (ways)." },
    { id:"ex-qn-19", type:"quantifiers", question:"The city has made _____ progress toward its sustainability goals this year.", options:["considerable","considerable many","many a","several"], answer:0, explanation:"'Considerable progress' = không đếm được." },
    { id:"ex-qn-20", type:"quantifiers", question:"_____ the board members expressed support for the green initiative at the meeting.", options:["Most of","Most","Almost all","The majority"], answer:0, explanation:"'Most of + the + noun' là dạng chuẩn xác nhất." },

    // ──────────────────────────────────────────────
    // BUSINESS-ENGLISH (Unit 21)
    // ──────────────────────────────────────────────
    { id:"ex-be-01", type:"business-english", question:"We would like to _____ a meeting for next Tuesday afternoon.", options:["schedule","conduct","perform","manage"], answer:0, explanation:"'Schedule a meeting' = lên lịch cuộc họp." },
    { id:"ex-be-02", type:"business-english", question:"Please _____ the attached proposal and provide your feedback.", options:["review","revise","revoke","reveal"], answer:0, explanation:"'Review a proposal' = xem xét đề xuất." },
    { id:"ex-be-03", type:"business-english", question:"We are writing to _____ our interest in the partnership opportunity.", options:["express","expose","expand","explain"], answer:0, explanation:"'Express interest' = bày tỏ sự quan tâm." },
    { id:"ex-be-04", type:"business-english", question:"The team will _____ the findings at the quarterly board meeting.", options:["present","provide","produce","propose"], answer:0, explanation:"'Present findings' = trình bày kết quả." },
    { id:"ex-be-05", type:"business-english", question:"Could you please _____ me with the updated sales figures?", options:["provide","present","produce","process"], answer:0, explanation:"'Provide someone with something' = cung cấp cho ai đó thứ gì." },
    { id:"ex-be-06", type:"business-english", question:"We look forward to _____ business with your esteemed organization.", options:["doing","making","having","taking"], answer:0, explanation:"'Doing business with' = làm ăn/kinh doanh cùng." },
    { id:"ex-be-07", type:"business-english", question:"I am writing to _____ my application for the position of Marketing Manager.", options:["submit","send","supply","support"], answer:0, explanation:"'Submit an application' = nộp đơn xin việc." },
    { id:"ex-be-08", type:"business-english", question:"Please do not hesitate to _____ us if you have any further questions.", options:["contact","connect","consult","conduct"], answer:0, explanation:"'Contact us' = liên hệ chúng tôi." },
    { id:"ex-be-09", type:"business-english", question:"We regret to _____ you that the project has been postponed.", options:["inform","indicate","instruct","involve"], answer:0, explanation:"'Regret to inform' = tiếc thông báo." },
    { id:"ex-be-10", type:"business-english", question:"We would like to _____ our sincere apologies for the inconvenience caused.", options:["extend","expand","export","express"], answer:0, explanation:"'Extend apologies' = gửi lời xin lỗi." },
    { id:"ex-be-11", type:"business-english", question:"As per your request, I have _____ the revised contract for your review.", options:["attached","added","applied","addressed"], answer:0, explanation:"'Attached the contract' = đính kèm hợp đồng." },
    { id:"ex-be-12", type:"business-english", question:"The project was completed _____ budget, saving the company $50,000.", options:["under","below","within","beneath"], answer:0, explanation:"'Under budget' = dưới ngân sách dự kiến." },
    { id:"ex-be-13", type:"business-english", question:"The company will _____ a new office in Singapore to support its Asian expansion.", options:["open","launch","set up","establish"], answer:3, explanation:"'Establish an office' = thành lập văn phòng (trang trọng nhất)." },
    { id:"ex-be-14", type:"business-english", question:"We need to _____ on the proposal before presenting it to the client.", options:["follow up","follow out","follow through","follow along"], answer:0, explanation:"'Follow up on' = theo dõi, tiếp nối." },
    { id:"ex-be-15", type:"business-english", question:"The director asked to be _____ of any developments regarding the acquisition.", options:["kept informed","informed keeping","keeping informed","keep informed"], answer:0, explanation:"'Kept informed of' = được thông tin liên tục." },
    { id:"ex-be-16", type:"business-english", question:"Please _____ the agenda before attending the strategy session.", options:["go over","go through","look at","check out"], answer:0, explanation:"'Go over the agenda' = xem lại/thảo luận chương trình họp." },
    { id:"ex-be-17", type:"business-english", question:"The quarterly review is _____ for the third week of October.", options:["scheduled","confirmed","arranged","booked"], answer:0, explanation:"'Scheduled for a date' = được lên lịch vào ngày." },
    { id:"ex-be-18", type:"business-english", question:"I would like to _____ a follow-up call to discuss the proposal in more detail.", options:["arrange","plan","make","do"], answer:0, explanation:"'Arrange a call' = sắp xếp cuộc gọi." },
    { id:"ex-be-19", type:"business-english", question:"The company is committed to _____ the highest standards of service.", options:["maintaining","meeting","following","supporting"], answer:0, explanation:"'Maintaining standards' = duy trì tiêu chuẩn." },
    { id:"ex-be-20", type:"business-english", question:"We would appreciate it if you could _____ our invoice at your earliest convenience.", options:["settle","pay","clear","handle"], answer:0, explanation:"'Settle an invoice' = thanh toán hóa đơn (từ trang trọng)." },

    // ──────────────────────────────────────────────
    // SUBJUNCTIVE (Unit 22 – Corporate Policy)
    // ──────────────────────────────────────────────
    { id:"ex-sj-01", type:"subjunctive", question:"The board recommended that the CEO _____ an independent audit.", options:["commission","commissions","commissioned","would commission"], answer:0, explanation:"'Recommend + that + S + V (base form)' = cấu trúc hư cách." },
    { id:"ex-sj-02", type:"subjunctive", question:"It is essential that all employees _____ the new data protection policy.", options:["follow","follows","followed","will follow"], answer:0, explanation:"'It is essential that + S + V (base form)'." },
    { id:"ex-sj-03", type:"subjunctive", question:"The manager insisted that the report _____ reviewed before distribution.", options:["be","is","was","would be"], answer:0, explanation:"'Insist that + S + be + past participle' = hư cách bị động." },
    { id:"ex-sj-04", type:"subjunctive", question:"It is vital that the financial records _____ accurate at all times.", options:["remain","remains","remained","will remain"], answer:0, explanation:"'It is vital that + S + V (base form)'." },
    { id:"ex-sj-05", type:"subjunctive", question:"The policy requires that every new hire _____ a background check.", options:["undergo","undergoes","underwent","would undergo"], answer:0, explanation:"'Require that + S + V (base form)'." },
    { id:"ex-sj-06", type:"subjunctive", question:"The committee proposed that the meeting _____ postponed until next month.", options:["be","is","was","should be"], answer:0, explanation:"'Propose that + S + be + past participle'." },
    { id:"ex-sj-07", type:"subjunctive", question:"It is imperative that each department head _____ the budget review.", options:["attend","attends","attended","would attend"], answer:0, explanation:"'It is imperative that + S + V (base form)'." },
    { id:"ex-sj-08", type:"subjunctive", question:"The legal team suggested that the contract _____ amended before signing.", options:["be","is","was","should"], answer:0, explanation:"'Suggest that + S + be + past participle'." },
    { id:"ex-sj-09", type:"subjunctive", question:"HR demanded that the manager _____ a formal apology to the affected staff.", options:["issue","issues","issued","has issued"], answer:0, explanation:"'Demand that + S + V (base form)'." },
    { id:"ex-sj-10", type:"subjunctive", question:"It is necessary that the new policies _____ communicated clearly to all staff.", options:["be","are","were","should be"], answer:0, explanation:"'It is necessary that + S + be + past participle'." },
    { id:"ex-sj-11", type:"subjunctive", question:"The director requested that the updated report _____ sent before 5 p.m.", options:["be","is","was","had been"], answer:0, explanation:"'Request that + S + be + past participle'." },
    { id:"ex-sj-12", type:"subjunctive", question:"It is crucial that the team _____ prepared for all possible scenarios.", options:["be","is","was","will be"], answer:0, explanation:"'It is crucial that + S + V (base form)'." },
    { id:"ex-sj-13", type:"subjunctive", question:"The auditor recommended that the internal controls _____ strengthened.", options:["be","are","were","should be"], answer:0, explanation:"'Recommend that + S + be + past participle'." },
    { id:"ex-sj-14", type:"subjunctive", question:"Management insisted that no changes _____ made without prior approval.", options:["be","are","were","would be"], answer:0, explanation:"'Insist that + S + be + past participle' (phủ định)." },
    { id:"ex-sj-15", type:"subjunctive", question:"It is important that the grievance procedure _____ fair and transparent.", options:["be","is","was","will be"], answer:0, explanation:"'It is important that + S + be + adj'." },
    { id:"ex-sj-16", type:"subjunctive", question:"The compliance officer required that all staff _____ the annual ethics course.", options:["complete","completes","completed","would complete"], answer:0, explanation:"'Require that + S + V (base form)'." },
    { id:"ex-sj-17", type:"subjunctive", question:"It is recommended that the applicant _____ three professional references.", options:["provide","provides","provided","will provide"], answer:0, explanation:"'It is recommended that + S + V (base form)'." },
    { id:"ex-sj-18", type:"subjunctive", question:"The supervisor urged that the team _____ more attention to detail.", options:["pay","pays","paid","would pay"], answer:0, explanation:"'Urge that + S + V (base form)'." },
    { id:"ex-sj-19", type:"subjunctive", question:"It is essential that no sensitive information _____ shared outside the organization.", options:["be","is","was","were"], answer:0, explanation:"'It is essential that + S + be + past participle'." },
    { id:"ex-sj-20", type:"subjunctive", question:"The board stipulated that each project _____ independently evaluated.", options:["be","is","was","should"], answer:0, explanation:"'Stipulate that + S + be + past participle'." },

    // ──────────────────────────────────────────────
    // PREP-STRUCTURES (Unit 23 – Advanced Structures)
    // ──────────────────────────────────────────────
    { id:"ex-ps-01", type:"prep-structures", question:"The strategy was carried out _____ accordance with the board's recommendations.", options:["in","on","by","at"], answer:0, explanation:"'In accordance with' = phù hợp với, theo." },
    { id:"ex-ps-02", type:"prep-structures", question:"The project was completed _____ spite of numerous technical challenges.", options:["in","on","at","by"], answer:0, explanation:"'In spite of' = mặc dù." },
    { id:"ex-ps-03", type:"prep-structures", question:"The decision was made _____ account of the rising operational costs.", options:["on","in","by","at"], answer:0, explanation:"'On account of' = vì lý do." },
    { id:"ex-ps-04", type:"prep-structures", question:"She was promoted _____ virtue of her outstanding performance.", options:["by","in","on","at"], answer:0, explanation:"'By virtue of' = nhờ vào." },
    { id:"ex-ps-05", type:"prep-structures", question:"All decisions must be made _____ line with company policy.", options:["in","on","by","at"], answer:0, explanation:"'In line with' = phù hợp với." },
    { id:"ex-ps-06", type:"prep-structures", question:"The consultant acted _____ behalf of the shareholders during negotiations.", options:["on","in","by","at"], answer:0, explanation:"'On behalf of' = thay mặt cho." },
    { id:"ex-ps-07", type:"prep-structures", question:"The acquisition was finalized _____ terms agreeable to both parties.", options:["on","in","by","at"], answer:0, explanation:"'On terms' = với các điều khoản." },
    { id:"ex-ps-08", type:"prep-structures", question:"The document was prepared _____ advance of the board meeting.", options:["in","on","by","at"], answer:0, explanation:"'In advance of' = trước." },
    { id:"ex-ps-09", type:"prep-structures", question:"The new regulations came _____ force last January.", options:["into","in","on","at"], answer:0, explanation:"'Come into force' = có hiệu lực." },
    { id:"ex-ps-10", type:"prep-structures", question:"The proposal fell _____ of management's expectations.", options:["short","down","out","behind"], answer:0, explanation:"'Fall short of' = không đáp ứng được." },
    { id:"ex-ps-11", type:"prep-structures", question:"The team worked _____ a tight deadline to deliver the final report.", options:["under","below","within","against"], answer:0, explanation:"'Under a tight deadline' = dưới áp lực thời hạn gấp." },
    { id:"ex-ps-12", type:"prep-structures", question:"The merger was approved _____ the condition that both companies retain their staff.", options:["on","in","at","by"], answer:0, explanation:"'On the condition that' = với điều kiện là." },
    { id:"ex-ps-13", type:"prep-structures", question:"His contribution to the project went _____ unnoticed for months.", options:["largely","large","larger","largely a"], answer:0, explanation:"'Went largely unnoticed' = phần lớn bị bỏ qua." },
    { id:"ex-ps-14", type:"prep-structures", question:"The results were _____ par with industry benchmarks.", options:["on","in","at","by"], answer:0, explanation:"'On par with' = ngang bằng với." },
    { id:"ex-ps-15", type:"prep-structures", question:"The product launch was put _____ hold due to regulatory delays.", options:["on","in","at","by"], answer:0, explanation:"'Put on hold' = hoãn lại." },
    { id:"ex-ps-16", type:"prep-structures", question:"The manager was _____ charge of coordinating all international shipments.", options:["in","on","at","by"], answer:0, explanation:"'In charge of' = phụ trách." },
    { id:"ex-ps-17", type:"prep-structures", question:"The company came _____ scrutiny following the financial audit.", options:["under","in","on","at"], answer:0, explanation:"'Come under scrutiny' = bị giám sát, xem xét kỹ." },
    { id:"ex-ps-18", type:"prep-structures", question:"The initiative was taken _____ the aim of reducing carbon emissions.", options:["with","for","by","on"], answer:0, explanation:"'With the aim of' = nhằm mục đích." },
    { id:"ex-ps-19", type:"prep-structures", question:"The deal was struck _____ the eleventh hour, just before the deadline.", options:["at","in","on","by"], answer:0, explanation:"'At the eleventh hour' = vào phút chót." },
    { id:"ex-ps-20", type:"prep-structures", question:"She took _____ the responsibilities of the role with great confidence.", options:["on","in","up","over"], answer:0, explanation:"'Take on responsibilities' = đảm nhận trách nhiệm." },

    // ──────────────────────────────────────────────
    // PART6-STRATEGY (Unit 17) – Part 5 standalone equivalents
    // ──────────────────────────────────────────────
    { id:"ex-p6s-01", type:"part6-strategy", question:"_____, we appreciate your prompt response to our inquiry.", options:["First and foremost","In addition","To summarize","In conclusion"], answer:0, explanation:"'First and foremost' = trước hết, mở đầu thư trang trọng." },
    { id:"ex-p6s-02", type:"part6-strategy", question:"Please note that the discount applies _____ to orders placed before December 31.", options:["only","ever","just","solely"], answer:0, explanation:"'Only' = chỉ, giới hạn phạm vi áp dụng." },
    { id:"ex-p6s-03", type:"part6-strategy", question:"We sincerely apologize for any inconvenience _____ by this delay.", options:["caused","causing","cause","to cause"], answer:0, explanation:"Past participle trong mệnh đề rút gọn." },
    { id:"ex-p6s-04", type:"part6-strategy", question:"_____ the survey results are reviewed, the team will prepare an action plan.", options:["Once","While","Until","Before"], answer:0, explanation:"'Once' = ngay khi kết quả được xem xét." },
    { id:"ex-p6s-05", type:"part6-strategy", question:"The committee will _____ the issue to senior management for a final decision.", options:["escalate","eliminate","evaluate","elevate"], answer:0, explanation:"'Escalate to senior management' = leo thang, chuyển lên cấp trên." },
    { id:"ex-p6s-06", type:"part6-strategy", question:"All applications must be _____ by the human resources department before processing.", options:["verified","clarified","modified","certified"], answer:0, explanation:"'Verified' = xác minh trước khi xử lý." },
    { id:"ex-p6s-07", type:"part6-strategy", question:"The report _____ detailed findings on employee satisfaction across all departments.", options:["contains","retains","maintains","sustains"], answer:0, explanation:"'Contains detailed findings' = báo cáo bao gồm." },
    { id:"ex-p6s-08", type:"part6-strategy", question:"We would be _____ if you could confirm receipt of this document.", options:["grateful","gracious","generous","genuine"], answer:0, explanation:"'Would be grateful if' = sẽ biết ơn nếu." },
    { id:"ex-p6s-09", type:"part6-strategy", question:"The terms outlined in the agreement are _____ to both negotiating parties.", options:["binding","bounding","bonding","blending"], answer:0, explanation:"'Binding' = ràng buộc pháp lý." },
    { id:"ex-p6s-10", type:"part6-strategy", question:"We look forward to _____ a mutually beneficial arrangement.", options:["reaching","arriving","achieving","attaining"], answer:0, explanation:"'Reaching an arrangement' = đạt được thỏa thuận." },
    { id:"ex-p6s-11", type:"part6-strategy", question:"Should you have any _____, please contact our support team immediately.", options:["concerns","concepts","conceptions","conclusions"], answer:0, explanation:"'Have concerns' = có lo ngại." },
    { id:"ex-p6s-12", type:"part6-strategy", question:"The revised budget will come _____ effect at the beginning of the next fiscal year.", options:["into","in","onto","on"], answer:0, explanation:"'Come into effect' = có hiệu lực." },
    { id:"ex-p6s-13", type:"part6-strategy", question:"Our team has been _____ tasked with overseeing the transition process.", options:["specifically","specially","speciously","speculatively"], answer:0, explanation:"'Specifically tasked with' = được giao nhiệm vụ cụ thể." },
    { id:"ex-p6s-14", type:"part6-strategy", question:"The decision to merge was made after _____ review of all available options.", options:["thorough","through","though","thought"], answer:0, explanation:"'Thorough review' = xem xét kỹ lưỡng." },
    { id:"ex-p6s-15", type:"part6-strategy", question:"We are pleased to _____ that your application has been approved.", options:["announce","denounce","pronounce","renounce"], answer:0, explanation:"'Pleased to announce' = vui mừng thông báo." },
    { id:"ex-p6s-16", type:"part6-strategy", question:"The attached document _____ a comprehensive overview of the proposed changes.", options:["provides","preserves","prevents","proceeds"], answer:0, explanation:"'Provides an overview' = cung cấp tổng quan." },
    { id:"ex-p6s-17", type:"part6-strategy", question:"I am writing _____ to your advertisement for the position of Senior Analyst.", options:["in response","in answer","in return","in reply"], answer:0, explanation:"'In response to' = để phúc đáp, trả lời." },
    { id:"ex-p6s-18", type:"part6-strategy", question:"The event will be held _____ unless there are unforeseen circumstances.", options:["as planned","as planning","as plans","as plan"], answer:0, explanation:"'As planned' = như kế hoạch." },
    { id:"ex-p6s-19", type:"part6-strategy", question:"Our client expects the project to be delivered _____ time and within budget.", options:["on","in","at","by"], answer:0, explanation:"'On time' = đúng hạn." },
    { id:"ex-p6s-20", type:"part6-strategy", question:"We _____ the opportunity to work with your distinguished organization.", options:["welcome","acknowledge","appreciate","value"], answer:0, explanation:"'Welcome the opportunity' = trân trọng cơ hội." },

    // ──────────────────────────────────────────────
    // PART7-STRATEGY (Unit 18) – Part 5 context-reading equivalents
    // ──────────────────────────────────────────────
    { id:"ex-p7s-01", type:"part7-strategy", question:"Based on the context, the word 'paramount' is closest in meaning to _____.", options:["most important","very large","widely known","clearly stated"], answer:0, explanation:"'Paramount' = tối quan trọng." },
    { id:"ex-p7s-02", type:"part7-strategy", question:"The word 'streamline' in a business context most likely means _____.", options:["make more efficient","make more complex","expand rapidly","reduce quality"], answer:0, explanation:"'Streamline' = tinh giản, tối ưu hóa quy trình." },
    { id:"ex-p7s-03", type:"part7-strategy", question:"The phrase 'in lieu of' means _____.", options:["instead of","in addition to","because of","prior to"], answer:0, explanation:"'In lieu of' = thay vì, thay thế cho." },
    { id:"ex-p7s-04", type:"part7-strategy", question:"The word 'mitigate' is closest in meaning to _____.", options:["reduce","remove","replace","reveal"], answer:0, explanation:"'Mitigate' = giảm nhẹ, giảm thiểu." },
    { id:"ex-p7s-05", type:"part7-strategy", question:"'At the discretion of' means _____.", options:["as decided by","in front of","after consulting with","in the opinion of"], answer:0, explanation:"'At the discretion of' = tùy theo quyết định của." },
    { id:"ex-p7s-06", type:"part7-strategy", question:"The word 'mandatory' most closely means _____.", options:["required","recommended","optional","preferred"], answer:0, explanation:"'Mandatory' = bắt buộc." },
    { id:"ex-p7s-07", type:"part7-strategy", question:"'Pending approval' means _____.", options:["awaiting approval","despite approval","after approval","before seeking approval"], answer:0, explanation:"'Pending' = đang chờ, chưa được duyệt." },
    { id:"ex-p7s-08", type:"part7-strategy", question:"The word 'unprecedented' is closest in meaning to _____.", options:["never happened before","happening frequently","well-established","difficult to predict"], answer:0, explanation:"'Unprecedented' = chưa từng xảy ra." },
    { id:"ex-p7s-09", type:"part7-strategy", question:"'Stipulate' in a contract context means _____.", options:["specify as a requirement","suggest an option","ignore a condition","remove a clause"], answer:0, explanation:"'Stipulate' = quy định rõ ràng, quy ước." },
    { id:"ex-p7s-10", type:"part7-strategy", question:"The word 'expedite' means _____.", options:["speed up","slow down","plan carefully","review thoroughly"], answer:0, explanation:"'Expedite' = thúc đẩy, tăng tốc." },
    { id:"ex-p7s-11", type:"part7-strategy", question:"'Comply with' means _____.", options:["follow a rule","question a rule","change a rule","ignore a rule"], answer:0, explanation:"'Comply with' = tuân thủ." },
    { id:"ex-p7s-12", type:"part7-strategy", question:"The phrase 'on a rolling basis' means _____.", options:["continuously as needed","once per year","only in emergencies","at fixed intervals only"], answer:0, explanation:"'On a rolling basis' = liên tục, theo chu kỳ cuộn." },
    { id:"ex-p7s-13", type:"part7-strategy", question:"'Remuneration' refers to _____.", options:["payment for work","training provided","vacation time","work schedule"], answer:0, explanation:"'Remuneration' = thù lao, tiền thưởng." },
    { id:"ex-p7s-14", type:"part7-strategy", question:"The word 'discrepancy' means _____.", options:["a difference or inconsistency","an improvement","a regulation","an agreement"], answer:0, explanation:"'Discrepancy' = sự khác biệt, không nhất quán." },
    { id:"ex-p7s-15", type:"part7-strategy", question:"'Commensurate with experience' means the salary _____.", options:["reflects the applicant's experience level","exceeds typical industry rates","is fixed regardless of background","is paid in advance"], answer:0, explanation:"'Commensurate with' = tương xứng với." },
    { id:"ex-p7s-16", type:"part7-strategy", question:"The word 'pursuant to' is closest in meaning to _____.", options:["in accordance with","in contrast to","in addition to","as a result of"], answer:0, explanation:"'Pursuant to' = chiếu theo, phù hợp với (văn bản pháp lý)." },
    { id:"ex-p7s-17", type:"part7-strategy", question:"'Tangible benefits' refers to benefits that are _____.", options:["real and measurable","abstract and subjective","future and uncertain","indirect and implied"], answer:0, explanation:"'Tangible' = hữu hình, cụ thể, đo lường được." },
    { id:"ex-p7s-18", type:"part7-strategy", question:"The phrase 'subject to change' means _____.", options:["may be changed later","will not be changed","has already been changed","is being changed now"], answer:0, explanation:"'Subject to change' = có thể thay đổi." },
    { id:"ex-p7s-19", type:"part7-strategy", question:"'Incumbent upon' means _____.", options:["the responsibility of","the choice of","the result of","the recommendation of"], answer:0, explanation:"'Incumbent upon' = là trách nhiệm/bổn phận của." },
    { id:"ex-p7s-20", type:"part7-strategy", question:"'Ratify an agreement' means _____.", options:["officially approve it","negotiate its terms","draft its contents","terminate it"], answer:0, explanation:"'Ratify' = phê chuẩn chính thức." },

  ];

  // Push extra Part 5 questions into the existing data bank
  if (!Array.isArray(TOEIC_QUESTIONS.part5)) TOEIC_QUESTIONS.part5 = [];
  EXTRA_PART5.forEach(q => {
    // Avoid duplicate IDs
    if (!TOEIC_QUESTIONS.part5.some(existing => existing.id === q.id)) {
      TOEIC_QUESTIONS.part5.push(q);
    }
  });

  console.log(`[TOEIC Extra] Đã thêm ${EXTRA_PART5.length} câu Part 5 bổ sung. Tổng Part 5: ${TOEIC_QUESTIONS.part5.length}`);
}
